// src/lib/prng.ts
export function mulberry32(seed: number) {
  return function() {
    let t = seed += 0x6D2B79F5;
    t = Math.imul(t ^ t >>> 15, t | 1);
    t ^= t + Math.imul(t ^ t >>> 7, t | 61);
    return ((t ^ t >>> 14) >>> 0) / 4294967296;
  };
}
export function hashSeed(s: string): number {
  let h = 2166136261;
  for (let i = 0; i < s.length; i++) { h ^= s.charCodeAt(i); h = Math.imul(h, 16777619); }
  return h >>> 0;
}

// src/lib/resetWindow.ts
import { DateTime } from 'luxon';
export function currentResetWindowStart(timezone: string, resetHour = 4): Date {
  const now = DateTime.now().setZone(timezone);
  let windowStart = now.set({ hour: resetHour, minute: 0, second: 0, millisecond: 0 });
  if (now < windowStart) windowStart = windowStart.minus({ days: 1 });
  return windowStart.toUTC().toJSDate();
}

// src/services/questService.ts
import { PlayerQuest, QuestDefinition, Player } from '../models';
import { mulberry32, hashSeed } from '../lib/prng';
import { currentResetWindowStart } from '../lib/resetWindow';

function weightedPick<T extends { weight: number }>(items: T[], rand: () => number, n: number): T[] {
  const pool = [...items];
  const picked: T[] = [];
  for (let i = 0; i < n && pool.length > 0; i++) {
    const total = pool.reduce((s, x) => s + x.weight, 0);
    let r = rand() * total;
    let idx = 0;
    for (; idx < pool.length; idx++) { r -= pool[idx].weight; if (r <= 0) break; }
    picked.push(pool[Math.min(idx, pool.length - 1)]);
    pool.splice(Math.min(idx, pool.length - 1), 1);
  }
  return picked;
}

export async function getOrGenerateDailyQuests(playerId: string) {
  const player = await Player.findById(playerId).lean();
  if (!player) throw new Error('player not found');
  const windowStart = currentResetWindowStart(player.timezone || 'UTC');
  let pq = await PlayerQuest.findOne({ player_id: playerId, window_start_utc: windowStart });
  if (pq) return pq;
  const seed = hashSeed(`${playerId}:${windowStart.getTime()}`);
  const rand = mulberry32(seed);
  const defs = await QuestDefinition.find({ min_level: { $lte: player.level } }).lean();
  const questCount = Math.min(5, 3 + Math.floor(player.level / 20));
  const chosen = weightedPick(defs, rand, questCount);
  const difficultyRoll = (lvl: number) => {
    const s = 1 / (1 + Math.exp(-0.1 * (lvl - 30)));
    const r = rand();
    if (r < s * 0.4) return { tier: 'hard', mult: 2.5 };
    if (r < 0.6) return { tier: 'med', mult: 1.5 };
    return { tier: 'easy', mult: 1.0 };
  };
  const quests = chosen.map(def => {
    const d = difficultyRoll(player.level);
    const baseXp = 100 * Math.pow(player.level, 1.4);
    return {
      quest_def_id: def._id,
      code: def.code,
      name: def.name,
      description: def.description,
      tier: d.tier,
      progress: 0,
      target: Math.ceil(def.base_target * d.mult),
      reward_xp: Math.ceil(baseXp * d.mult * 0.15),
      reward_currency: Math.ceil(def.base_reward_currency * d.mult),
      claimed: false
    };
  });
  const expires = new Date(windowStart.getTime() + 48 * 3600 * 1000);
  pq = await PlayerQuest.create({ player_id: playerId, window_start_utc: windowStart, quests, expires_at: expires });
  return pq;
}

