// src/hooks/useDailyQuests.ts
import { useEffect, useState } from 'react';
import { DateTime } from 'luxon';
export function useDailyQuests() {
  const [data, setData] = useState<any>(null);
  const [timeUntilReset, setTimeUntilReset] = useState('');
  useEffect(() => {
    fetch('/api/quests/daily').then(r => r.json()).then(setData);
  }, []);
  useEffect(() => {
    if (!data) return;
    const tick = () => {
      const reset = DateTime.fromISO(data.window_start).plus({ hours: 24 });
      const diff = reset.diffNow(['hours', 'minutes', 'seconds']);
      setTimeUntilReset(`${Math.floor(diff.hours)}h ${Math.floor(diff.minutes)}m`);
    };
    tick();
    const id = setInterval(tick, 1000);
    return () => clearInterval(id);
  }, [data]);
  return { data, timeUntilReset, refresh: () => fetch('/api/quests/daily').then(r => r.json()).then(setData) };
}

