// src/services/gachaService.ts
import { db } from '../db';
import { mulberry32, hashSeed } from '../lib/prng';

interface BannerConfig {
  bannerId: string;
  ratesByRarity: { common: number; rare: number; epic: number; legendary: number };
  softPityStart: number; // pull index from which legendary rate increases
  softPityIncrement: number; // additional probability per pull past threshold
  hardPity: number; // guaranteed legendary at this pull
  featuredLegendaryId: string;
  standardLegendaryPool: string[];
  rarePool: string[];
  epicPool: string[];
  commonPool: string[];
  costPerPull: number;
}

function legendaryRate(cfg: BannerConfig, pityCounter: number): number {
  if (pityCounter + 1 >= cfg.hardPity) return 1.0;
  if (pityCounter + 1 < cfg.softPityStart) return cfg.ratesByRarity.legendary;
  const over = (pityCounter + 1) - cfg.softPityStart + 1;
  return Math.min(1, cfg.ratesByRarity.legendary + over * cfg.softPityIncrement);
}

function rollRarity(rand: () => number, cfg: BannerConfig, pityCounter: number): 'legendary' | 'epic' | 'rare' | 'common' {
  const legRate = legendaryRate(cfg, pityCounter);
  const r = rand();
  if (r < legRate) return 'legendary';
  const remaining = 1 - legRate;
  const epicShare = cfg.ratesByRarity.epic / (1 - cfg.ratesByRarity.legendary);
  const rareShare = cfg.ratesByRarity.rare / (1 - cfg.ratesByRarity.legendary);
  const r2 = (r - legRate) / remaining;
  if (r2 < epicShare) return 'epic';
  if (r2 < epicShare + rareShare) return 'rare';
  return 'common';
}

export async function executePull(playerId: string, bannerId: string, count: number) {
  if (count < 1 || count > 10) throw new Error('invalid count');
  return db.transaction(async tx => {
    const state = await tx.one(`SELECT * FROM player_gacha_state WHERE player_id=$1 AND banner_id=$2 FOR UPDATE`, [playerId, bannerId]);
    const cfg = await loadBannerConfig(bannerId);
    const totalCost = cfg.costPerPull * count;
    const player = await tx.one(`SELECT premium_currency FROM players WHERE id=$1 FOR UPDATE`, [playerId]);
    if (player.premium_currency < totalCost) throw new Error('insufficient currency');
    await tx.none(`UPDATE players SET premium_currency = premium_currency - $1 WHERE id=$2`, [totalCost, playerId]);
    const results: any[] = [];
    let pity = state.pity_counter;
    let lastLegFeatured = state.last_legendary_was_featured;
    for (let i = 0; i < count; i++) {
      const seed = hashSeed(`${playerId}:${bannerId}:${state.total_pulls_lifetime + i}`);
      const rand = mulberry32(seed);
      const rarity = rollRarity(rand, cfg, pity);
      let itemId: string;
      let wasFeatured = false;
      if (rarity === 'legendary') {
        if (!lastLegFeatured) { itemId = cfg.featuredLegendaryId; wasFeatured = true; }
        else { wasFeatured = rand() < 0.5; itemId = wasFeatured ? cfg.featuredLegendaryId : pickRandom(cfg.standardLegendaryPool, rand); }
        lastLegFeatured = wasFeatured;
        pity = 0;
      } else if (rarity === 'epic') { itemId = pickRandom(cfg.epicPool, rand); pity += 1; }
      else if (rarity === 'rare') { itemId = pickRandom(cfg.rarePool, rand); pity += 1; }
      else { itemId = pickRandom(cfg.commonPool, rand); pity += 1; }
      await tx.none(`INSERT INTO gacha_pull(player_id, banner_id, pity_counter_before, pity_counter_after, rolled_rarity, rolled_item_id, was_featured, currency_spent, seed_used) VALUES ($1,$2,$3,$4,$5,$6,$7,$8,$9)`,
        [playerId, bannerId, pity === 0 ? state.pity_counter + i : pity - 1, pity, rarity, itemId, wasFeatured, cfg.costPerPull, seed]);
      results.push({ rarity, itemId, wasFeatured, newPity: pity });
      await grantItem(tx, playerId, itemId);
    }
    await tx.none(`UPDATE player_gacha_state SET pity_counter=$1, last_legendary_was_featured=$2, total_pulls_lifetime = total_pulls_lifetime + $3 WHERE player_id=$4 AND banner_id=$5`, [pity, lastLegFeatured, count, playerId, bannerId]);
    return { results, newPity: pity, lastLegFeatured };
  });
}

function pickRandom<T>(arr: T[], rand: () => number): T { return arr[Math.floor(rand() * arr.length)]; }

// src/routes/gacha.ts — REGULATORY: drop rates endpoint MUST exist
import { Router } from 'express';
import { executePull } from '../services/gachaService';
import { loadBannerConfig } from '../services/banner';
const r = Router();
r.get('/banner/:id/rates', async (req, res) => {
  const cfg = await loadBannerConfig(req.params.id);
  const expectedPullsToLegendary = computeExpectedPulls(cfg);
  res.json({ rates: cfg.ratesByRarity, softPityStart: cfg.softPityStart, hardPity: cfg.hardPity, expectedPullsToLegendary, featuredLegendary: cfg.featuredLegendaryId, standardLegendaryPool: cfg.standardLegendaryPool });
});
r.post('/pull', requireAuth, rateLimit({ windowMs: 1000, max: 2 }), async (req, res) => {
  const { bannerId, count } = req.body;
  const result = await executePull(req.user.id, bannerId, count);
  res.json(result);
});
export default r;

