  const sortedResults = [...results].sort((a, b) => {
    const rank = { common: 0, rare: 1, epic: 2, legendary: 3 };
    return rank[a.rarity as keyof typeof rank] - rank[b.rarity as keyof typeof rank];
  });
  useEffect(() => {
    let idx = -1;
