// src/services/achievementEvaluator.ts
import { AchievementDef, PlayerAchievement } from '../models';
import { pushNotification } from './notificationService';
import { Player } from '../models';

const defsByEventCache = new Map<string, any[]>();
async function defsForEvent(eventType: string) {
  if (defsByEventCache.has(eventType)) return defsByEventCache.get(eventType)!;
  const defs = await AchievementDef.find({ event_type: eventType }).lean();
  defsByEventCache.set(eventType, defs);
  setTimeout(() => defsByEventCache.delete(eventType), 60000);
  return defs;
}

function matchesCondition(event: any, cond: any): boolean {
  if (!cond) return true;
  const val = event[cond.field];
  switch (cond.op) { case 'eq': return val === cond.value; case 'gte': return val >= cond.value; case 'in': return cond.value.includes(val); default: return false; }
}

export async function processEvent(playerId: string, eventType: string, event: any, increment = 1) {
  const defs = await defsForEvent(eventType);
  for (const def of defs) {
    if (!matchesCondition(event, def.condition)) continue;
    const existing = await PlayerAchievement.findOne({ player_id: playerId, achievement_code: def.code });
    const prevProgress = existing?.progress ?? 0;
    const prevTierIdx = existing?.current_tier_idx ?? -1;
    const newProgress = prevProgress + increment;
    let newTierIdx = prevTierIdx;
    const tierUnlocks: any[] = [];
    for (let i = prevTierIdx + 1; i < def.tiers.length; i++) {
      if (newProgress >= def.tiers[i].threshold) { newTierIdx = i; tierUnlocks.push({ tier_idx: i, unlocked_at: new Date() }); }
      else break;
    }
    const updated = await PlayerAchievement.findOneAndUpdate(
      { player_id: playerId, achievement_code: def.code, version: existing?.version ?? 0 },
      { $set: { progress: newProgress, current_tier_idx: newTierIdx }, $push: { tier_unlocked_at: { $each: tierUnlocks } }, $inc: { version: 1 }, $setOnInsert: { player_id: playerId, achievement_code: def.code } },
      { upsert: true, new: true }
    );
    if (tierUnlocks.length > 0) {
      const globalRate = await getGlobalUnlockRate(def.code, newTierIdx);
      const rarity = -Math.log10(Math.max(globalRate, 0.0001));
      for (const t of tierUnlocks) {
        await pushNotification(playerId, {
          type: 'achievement_unlocked',
          priority: rarity * 10 + Date.now() / 1e12,
          payload: { code: def.code, name: def.name, tier: def.tiers[t.tier_idx].name, tier_idx: t.tier_idx, rarity, global_unlock_pct: globalRate * 100, reward_points: def.tiers[t.tier_idx].reward_points, hidden: def.hidden }
        });
        await Player.updateOne({ _id: playerId }, { $inc: { achievement_points_total: def.tiers[t.tier_idx].reward_points, premium_currency: def.tiers[t.tier_idx].reward_currency } });
      }
    }
  }
}

async function getGlobalUnlockRate(code: string, tierIdx: number): Promise<number> {
  const total = await Player.estimatedDocumentCount();
  const unlocked = await PlayerAchievement.countDocuments({ achievement_code: code, current_tier_idx: { $gte: tierIdx } });
  return unlocked / Math.max(total, 1);
}

// src/services/notificationService.ts
import { redis } from '../redis';
import { io } from '../socket';
export async function pushNotification(playerId: string, notif: any) {
  await redis.zadd(`notif:queue:${playerId}`, notif.priority, JSON.stringify(notif));
  await redis.expire(`notif:queue:${playerId}`, 3600);
  io.to(`player:${playerId}`).emit('notification', notif);
}

// src/jobs/retroactiveBackfill.ts — runs when new achievement def added
import { Queue, Worker } from 'bullmq';
import { PlayerStats, AchievementDef } from '../models';
import { processEvent } from '../services/achievementEvaluator';
export const retroactiveQueue = new Queue('retroactive-achievements');
new Worker('retroactive-achievements', async job => {
  const { achievementCode } = job.data;
  const def = await AchievementDef.findOne({ code: achievementCode });
  if (!def) return;
  const cursor = PlayerStats.find({}).cursor();
  for await (const stats of cursor) {
    const aggregateValue = stats[def.condition.field] ?? 0;
    if (aggregateValue > 0) await processEvent(stats.player_id, def.event_type, { [def.condition.field]: stats[def.condition.field] }, aggregateValue);
  }
});

