// src/components/AchievementNotificationStack.tsx
import { useEffect, useState, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useSocket } from '../hooks/useSocket';
const tierColors = { bronze: 'from-amber-700 to-amber-900', silver: 'from-slate-300 to-slate-500', gold: 'from-yellow-300 to-yellow-600', platinum: 'from-cyan-200 to-violet-400' };
export function AchievementNotificationStack() {
  const [visible, setVisible] = useState<any[]>([]);
  const queueRef = useRef<any[]>([]);
  const socket = useSocket();
  useEffect(() => {
    const onNotif = (n: any) => { if (n.type !== 'achievement_unlocked') return; queueRef.current.push(n); processQueue(); };
    socket.on('notification', onNotif);
    return () => { socket.off('notification', onNotif); };
  }, [socket]);
  const processQueue = () => {
    if (visible.length >= 3) return;
    if (queueRef.current.length === 0) return;
    queueRef.current.sort((a, b) => b.priority - a.priority);
    const next = queueRef.current.shift();
    setVisible(v => [...v, { ...next, id: Date.now() + Math.random() }]);
    const displayMs = Math.min(6000, 2000 + (next.payload.rarity || 0) * 1000);
    setTimeout(() => { setVisible(v => v.filter(x => x.id !== (next as any).id)); setTimeout(processQueue, 200); }, displayMs);
  };
  useEffect(() => { const i = setInterval(processQueue, 500); return () => clearInterval(i); }, []);
  return (
    <div className='fixed top-6 right-6 z-40 flex flex-col gap-3 pointer-events-none'>
      <AnimatePresence>
        {visible.map(n => {
          const tier = n.payload.tier as keyof typeof tierColors;
          const isLegendary = n.payload.rarity >= 2.0;
          return (
            <motion.div key={n.id} initial={{ x: 400, opacity: 0 }} animate={{ x: 0, opacity: 1 }} exit={{ x: 400, opacity: 0 }} transition={{ type: 'spring', stiffness: 300, damping: 25 }}
              className={`relative w-80 p-4 rounded-xl bg-gradient-to-br ${tierColors[tier]} text-white shadow-2xl overflow-hidden`}>
              {isLegendary && <motion.div className='absolute inset-0 bg-white' initial={{ opacity: 0.6 }} animate={{ opacity: 0 }} transition={{ duration: 1.2 }} />}
              <div className='relative flex items-center gap-3'>
