// src/services/notificationDispatcher.ts
import { admin } from '../firebase';
import { PlayerNotificationPrefs, NotificationLog, NotificationQueue } from '../models';
import { DateTime } from 'luxon';

interface NotifRequest { playerId: string; type: string; payload: any; urgency: 'urgent' | 'high' | 'normal' | 'low'; }

export async function requestNotification(req: NotifRequest) {
  const prefs = await PlayerNotificationPrefs.findOne({ player_id: req.playerId });
  if (!prefs || !prefs.push_enabled) { await logToInApp(req); return; }
  if (prefs.category_prefs[req.type] === 'off') return;
  const now = DateTime.now().setZone(prefs.sleep_window.timezone);
  const inSleep = isInSleepWindow(now, prefs.sleep_window);
  if (inSleep && req.urgency !== 'urgent') { await queueForLater(req, prefs); return; }
  const sentToday = await NotificationLog.countDocuments({ player_id: req.playerId, sent_at: { $gte: startOfDay(prefs.sleep_window.timezone) } });
  if (sentToday >= prefs.frequency_cap_daily && req.urgency !== 'urgent') { await queueForTomorrow(req, prefs); return; }
  const bundleCandidate = await NotificationLog.findOne({ player_id: req.playerId, sent_at: { $gte: new Date(Date.now() - 15 * 60 * 1000) }, opened_at: null });
  if (bundleCandidate && req.urgency === 'normal') { await mergeIntoBundle(bundleCandidate, req); return; }
  await sendPush(req, prefs);
}

function isInSleepWindow(now: DateTime, sw: { start_hour: number; end_hour: number }): boolean {
  const h = now.hour + now.minute / 60;
  if (sw.start_hour < sw.end_hour) return h >= sw.start_hour && h < sw.end_hour;
  return h >= sw.start_hour || h < sw.end_hour;
}

async function sendPush(req: NotifRequest, prefs: any) {
  const log = await NotificationLog.create({ player_id: req.playerId, type: req.type, payload: req.payload, priority: computePriority(req), sent_at: new Date(), device_id: prefs.primary_device_id });
  await admin.messaging().send({
    token: prefs.fcm_token,
    notification: { title: req.payload.title, body: req.payload.body, imageUrl: req.payload.image_url },
    data: { type: req.type, deep_link: req.payload.deep_link, log_id: log._id.toString() },
    android: { priority: req.urgency === 'urgent' ? 'high' : 'normal' },
    apns: { headers: { 'apns-priority': req.urgency === 'urgent' ? '10' : '5' } }
  });
}

function computePriority(req: NotifRequest): number {
  const base = { urgent: 100, high: 50, normal: 20, low: 5 }[req.urgency];
  return base;
}

async function queueForLater(req: NotifRequest, prefs: any) {
  const now = DateTime.now().setZone(prefs.sleep_window.timezone);
  let wakeup = now.set({ hour: prefs.sleep_window.end_hour, minute: 0 });
  if (wakeup < now) wakeup = wakeup.plus({ days: 1 });
  await NotificationQueue.updateOne({ player_id: req.playerId }, { $push: { items: { ...req, scheduled_for: wakeup.toJSDate() } } }, { upsert: true });
}

async function mergeIntoBundle(bundle: any, req: NotifRequest) {
  await NotificationLog.updateOne({ _id: bundle._id }, { $push: { bundled_with: { type: req.type, payload: req.payload, added_at: new Date() } } });
}

// src/jobs/sleepWindowRecompute.ts — runs daily per player
import { Worker } from 'bullmq';
import { Player, PlayerNotificationPrefs } from '../models';
new Worker('sleep-window-recompute', async job => {
  const { playerId } = job.data;
  const sessions = await Player.findById(playerId).then(p => p?.last_session_timestamps || []);
  if (sessions.length < 30) return;
  const tz = (await PlayerNotificationPrefs.findOne({ player_id: playerId }))?.sleep_window.timezone || 'UTC';
  const bins = new Array(24).fill(0);
  for (const ts of sessions) { const h = DateTime.fromJSDate(ts).setZone(tz).hour; bins[h] += 1; }
  const maxBin = Math.max(...bins);
  const threshold = maxBin * 0.05;
  let bestStart = 0, bestLen = 0, currStart = -1, currLen = 0;
  for (let i = 0; i < 48; i++) {
    const h = i % 24;
    if (bins[h] <= threshold) { if (currStart === -1) currStart = h; currLen += 1; if (currLen > bestLen) { bestLen = currLen; bestStart = currStart; } }
    else { currStart = -1; currLen = 0; }
  }
  if (bestLen >= 4) {
    await PlayerNotificationPrefs.updateOne({ player_id: playerId }, { $set: { 'sleep_window.start_hour': bestStart % 24, 'sleep_window.end_hour': (bestStart + bestLen) % 24 } });
  }
});

