// src/services/economyService.ts
import { db } from '../db';

export type Reason = 'daily_quest' | 'match_win' | 'login_bonus' | 'gift_received' | 'shop_purchase' | 'gem_purchase' | 'refund' | 'admin_grant';

export async function applyCurrencyChange(opts: {
  playerId: string;
  currency: 'soft' | 'hard';
  delta: number;
  reason: Reason;
  referenceId: string;
  idempotencyKey: string;
}): Promise<{ newBalance: number }> {
  return db.tx(async tx => {
    const existing = await tx.oneOrNone('SELECT 1 FROM currency_transaction WHERE idempotency_key = $1', [opts.idempotencyKey]);
    if (existing) {
      const p = await tx.one('SELECT soft_balance, hard_balance FROM players WHERE id=$1', [opts.playerId]);
      return { newBalance: opts.currency === 'soft' ? p.soft_balance : p.hard_balance };
    }
    const balCol = opts.currency === 'soft' ? 'soft_balance' : 'hard_balance';
    const player = await tx.one(`SELECT ${balCol} as bal FROM players WHERE id=$1 FOR UPDATE`, [opts.playerId]);
    const newBal = player.bal + opts.delta;
    if (newBal < 0) throw new Error('insufficient_balance');
    await tx.none(`UPDATE players SET ${balCol} = $1 WHERE id=$2`, [newBal, opts.playerId]);
    await tx.none('INSERT INTO currency_transaction(player_id, currency, delta, reason, reference_id, balance_before, balance_after, idempotency_key) VALUES ($1,$2,$3,$4,$5,$6,$7,$8)',
      [opts.playerId, opts.currency, opts.delta, opts.reason, opts.referenceId, player.bal, newBal, opts.idempotencyKey]);
    return { newBalance: newBal };
  });
}

