  const sku = await loadSku(skuCode);
  if (!sku) throw new Error('unknown_sku');
  if (sku.expires_at && sku.expires_at < new Date()) throw new Error('sku_expired');
  await applyCurrencyChange({ playerId, currency: sku.currency, delta: -sku.cost, reason: 'shop_purchase', referenceId: skuCode, idempotencyKey });
  await grantContents(playerId, sku.contents, idempotencyKey + ':grant');
  return { success: true };
}

