import fetch from 'node-fetch';
export async function verifyApplePurchase(receiptB64: string): Promise<{ valid: boolean; productId: string; transactionId: string } | null> {
  const r = await fetch('https://buy.itunes.apple.com/verifyReceipt', { method: 'POST', body: JSON.stringify({ 'receipt-data': receiptB64, password: process.env.APPLE_SHARED_SECRET }) });
  const data: any = await r.json();
  if (data.status !== 0) return null;
  const latest = data.latest_receipt_info?.[0] ?? data.receipt.in_app[0];
  return { valid: true, productId: latest.product_id, transactionId: latest.transaction_id };
}
export async function processGemPurchase(playerId: string, store: 'apple' | 'google', receipt: string) {
  const verified = store === 'apple' ? await verifyApplePurchase(receipt) : await verifyGooglePurchase(receipt);
  if (!verified) throw new Error('invalid_receipt');
  const existing = await db.oneOrNone('SELECT 1 FROM pending_purchases WHERE receipt_id=$1 AND processed_at IS NOT NULL', [verified.transactionId]);
  if (existing) return { duplicate: true };
  const sku = await loadGemSku(verified.productId);
  await db.none('INSERT INTO pending_purchases(receipt_id, store, player_id, sku, gems_amount) VALUES ($1,$2,$3,$4,$5) ON CONFLICT (receipt_id) DO NOTHING', [verified.transactionId, store, playerId, verified.productId, sku.gems]);
  await applyCurrencyChange({ playerId, currency: 'hard', delta: sku.gems, reason: 'gem_purchase', referenceId: verified.transactionId, idempotencyKey: 'iap:' + verified.transactionId });
  await db.none('UPDATE pending_purchases SET processed_at = NOW() WHERE receipt_id = $1', [verified.transactionId]);
  return { success: true, gemsAdded: sku.gems };
}

