new Worker('inflation-monitor', async () => {
  const stats = await db.one(`
    SELECT
      SUM(CASE WHEN delta > 0 AND currency='soft' THEN delta ELSE 0 END) AS faucet,
      SUM(CASE WHEN delta < 0 AND currency='soft' THEN -delta ELSE 0 END) AS sink,
      (SELECT SUM(soft_balance) FROM players WHERE last_login > NOW() - INTERVAL '14 days') AS circulation
    FROM currency_transaction WHERE created_at > NOW() - INTERVAL '7 days'
  `);
  const inflation = stats.circulation > 0 ? (stats.faucet - stats.sink) / stats.circulation : 0;
  await db.none('INSERT INTO economy_health(snapshot_at, faucet_7d, sink_7d, circulation, inflation_rate) VALUES (NOW(), $1, $2, $3, $4)', [stats.faucet, stats.sink, stats.circulation, inflation]);
  if (inflation > 0.03) await alertOps(`Soft currency inflation ${(inflation*100).toFixed(2)}% — consider tuning down faucets`);
});

