// src/services/insightGenerator.ts
import { db } from '../db';
import { PlayerInsights } from '../models';

interface Insight { headline: string; detail: string; sentiment: 'positive' | 'neutral' | 'warning'; surprise: number; supporting: any; }

function tTest(a: number[], b: number[]): { t: number; p: number; cohenD: number } {
  const meanA = a.reduce((s, x) => s + x, 0) / a.length;
  const meanB = b.reduce((s, x) => s + x, 0) / b.length;
  const varA = a.reduce((s, x) => s + (x - meanA) ** 2, 0) / (a.length - 1);
  const varB = b.reduce((s, x) => s + (x - meanB) ** 2, 0) / (b.length - 1);
  const pooledSd = Math.sqrt((varA + varB) / 2);
  const cohenD = pooledSd > 0 ? (meanA - meanB) / pooledSd : 0;
  const se = Math.sqrt(varA / a.length + varB / b.length);
  const t = se > 0 ? (meanA - meanB) / se : 0;
  const df = a.length + b.length - 2;
  const p = 2 * (1 - studentTCdf(Math.abs(t), df));
  return { t, p, cohenD };
}

function studentTCdf(t: number, df: number): number {
  const x = df / (t * t + df);
  const a = 0.5 * df, b = 0.5;
  return 1 - 0.5 * incBeta(x, a, b);
}
function incBeta(x: number, a: number, b: number): number { /* numerical approximation */ return 0; }

export async function generateInsights(playerId: string): Promise<Insight[]> {
  const matches = await db.any('SELECT * FROM matches WHERE player_id=$1 AND ended_at > NOW() - INTERVAL '90 days' ORDER BY ended_at', [playerId]);
  if (matches.length < 30) return [];
  const insights: Insight[] = [];
  insights.push(...timeOfDayInsights(matches));
  insights.push(...mapPerformanceInsights(matches));
  insights.push(...sessionFatigueInsights(matches));
  insights.push(...trendInsights(matches));
  insights.sort((a, b) => b.surprise - a.surprise);
  return insights.slice(0, 5);
}

function timeOfDayInsights(matches: any[]): Insight[] {
  const buckets: Record<string, number[]> = { morning: [], afternoon: [], evening: [], night: [] };
  for (const m of matches) {
    const h = new Date(m.ended_at).getHours();
    const b = h < 12 ? 'morning' : h < 17 ? 'afternoon' : h < 22 ? 'evening' : 'night';
    buckets[b].push(m.result === 'W' ? 1 : 0);
  }
  const out: Insight[] = [];
  for (const [name, samples] of Object.entries(buckets)) {
    if (samples.length < 15) continue;
    const others = matches.filter(m => { const h = new Date(m.ended_at).getHours(); const b = h < 12 ? 'morning' : h < 17 ? 'afternoon' : h < 22 ? 'evening' : 'night'; return b !== name; }).map(m => m.result === 'W' ? 1 : 0);
    if (others.length < 15) continue;
    const { p, cohenD } = tTest(samples, others);
    if (p < 0.05 && Math.abs(cohenD) > 0.3) {
      const wrThis = samples.reduce((s, x) => s + x, 0) / samples.length;
      const wrOther = others.reduce((s, x) => s + x, 0) / others.length;
      const deltaPct = ((wrThis - wrOther) / wrOther * 100).toFixed(0);
      out.push({
        headline: `You win ${Math.abs(parseInt(deltaPct))}% ${parseFloat(deltaPct) > 0 ? 'more' : 'less'} in the ${name}`,
        detail: `${(wrThis * 100).toFixed(0)}% win rate ${name}, vs ${(wrOther * 100).toFixed(0)}% other times. Sample: ${samples.length} matches.`,
        sentiment: parseFloat(deltaPct) > 0 ? 'positive' : 'warning',
        surprise: -Math.log10(p) * Math.abs(cohenD),
        supporting: { window: name, winRate: wrThis, baseline: wrOther }
      });
    }
  }
  return out;
}

function sessionFatigueInsights(matches: any[]): Insight[] {
  const sorted = [...matches].sort((a, b) => new Date(a.ended_at).getTime() - new Date(b.ended_at).getTime());
  const positions: number[] = [];
  const kdas: number[] = [];
  let pos = 0;
  let prevEnd = 0;
  for (const m of sorted) {
    const startGap = new Date(m.ended_at).getTime() - prevEnd;
    if (startGap > 30 * 60 * 1000) pos = 0;
    pos += 1;
    positions.push(pos);
    kdas.push((m.kills + m.assists) / Math.max(1, m.deaths));
    prevEnd = new Date(m.ended_at).getTime();
  }
  const earlyKda = kdas.filter((_, i) => positions[i] <= 3);
  const lateKda = kdas.filter((_, i) => positions[i] >= 4);
  if (earlyKda.length < 15 || lateKda.length < 15) return [];
  const { p, cohenD } = tTest(earlyKda, lateKda);
  if (p < 0.05 && cohenD > 0.3) {
    const drop = ((earlyKda.reduce((s,x)=>s+x,0)/earlyKda.length) - (lateKda.reduce((s,x)=>s+x,0)/lateKda.length)) / (earlyKda.reduce((s,x)=>s+x,0)/earlyKda.length) * 100;
    return [{ headline: `Your KDA drops ${drop.toFixed(0)}% after 4+ matches`, detail: `Consider shorter sessions for peak performance.`, sentiment: 'warning', surprise: -Math.log10(p) * cohenD, supporting: { earlyAvg: earlyKda.length, lateAvg: lateKda.length } }];
  }
  return [];
}

function mapPerformanceInsights(matches: any[]): Insight[] {
  const byMap: Record<string, any[]> = {};
  for (const m of matches) { (byMap[m.map] ??= []).push(m); }
  const out: Insight[] = [];
  for (const [map, ms] of Object.entries(byMap)) {
    if (ms.length < 10) continue;
    const wr = ms.filter(m => m.result === 'W').length / ms.length;
    const overall = matches.filter(m => m.result === 'W').length / matches.length;
    if (Math.abs(wr - overall) > 0.15) {
      out.push({ headline: `You're a ${wr > overall ? 'monster' : 'struggle'} on ${map}`, detail: `${(wr * 100).toFixed(0)}% win rate on ${map} vs ${(overall * 100).toFixed(0)}% overall (${ms.length} matches).`, sentiment: wr > overall ? 'positive' : 'warning', surprise: Math.abs(wr - overall) * 5, supporting: { map, winRate: wr } });
    }
  }
  return out;
}

function trendInsights(matches: any[]): Insight[] { return []; /* linear regression on rolling win rate */ }

export async function refreshInsights(playerId: string) {
  const insights = await generateInsights(playerId);
  await PlayerInsights.replaceOne({ player_id: playerId }, { player_id: playerId, insights, expires_at: new Date(Date.now() + 24 * 3600 * 1000) }, { upsert: true });
}

