// src/services/glicko2.ts
const TAU = 0.5;
const Q = Math.log(10) / 400;
export interface GlickoState { rating: number; rd: number; sigma: number; }
export function defaultState(): GlickoState { return { rating: 1500, rd: 350, sigma: 0.06 }; }
function g(phi: number) { return 1 / Math.sqrt(1 + 3 * phi * phi / (Math.PI * Math.PI)); }
function expected(mu: number, muJ: number, phiJ: number) { return 1 / (1 + Math.exp(-g(phiJ) * (mu - muJ))); }

export function updateGlicko(self: GlickoState, results: Array<{ opp: GlickoState; score: number }>): GlickoState {
  const mu = (self.rating - 1500) / 173.7178;
  const phi = self.rd / 173.7178;
  let v = 0;
  let delta_inner = 0;
  for (const r of results) {
    const muJ = (r.opp.rating - 1500) / 173.7178;
    const phiJ = r.opp.rd / 173.7178;
    const E = expected(mu, muJ, phiJ);
    v += g(phiJ) * g(phiJ) * E * (1 - E);
    delta_inner += g(phiJ) * (r.score - E);
  }
  v = 1 / v;
  const delta = v * delta_inner;
  const sigma2 = self.sigma * self.sigma;
  const a = Math.log(sigma2);
  const f = (x: number) => (Math.exp(x) * (delta * delta - phi * phi - v - Math.exp(x))) / (2 * (phi * phi + v + Math.exp(x)) ** 2) - (x - a) / (TAU * TAU);
  let A = a;
  let B = delta * delta > phi * phi + v ? Math.log(delta * delta - phi * phi - v) : a - TAU;
  while (f(B) < 0) B -= TAU;
  let fA = f(A), fB = f(B);
  for (let i = 0; i < 100 && Math.abs(B - A) > 1e-6; i++) {
    const C = A + (A - B) * fA / (fB - fA);
    const fC = f(C);
    if (fC * fB <= 0) { A = B; fA = fB; } else { fA = fA / 2; }
    B = C; fB = fC;
  }
  const newSigma = Math.exp(A / 2);
  const phiStar = Math.sqrt(phi * phi + newSigma * newSigma);
  const newPhi = 1 / Math.sqrt(1 / (phiStar * phiStar) + 1 / v);
  const newMu = mu + newPhi * newPhi * delta_inner;
  return { rating: newMu * 173.7178 + 1500, rd: newPhi * 173.7178, sigma: newSigma };
}

// src/services/matchmaker.ts
import { redis } from '../redis';
import { db } from '../db';

interface QueueEntry { playerId: string; partyId: string; rating: number; rd: number; preferredRoles: string[]; enqueueMs: number; }

function acceptableSkillGap(waitSec: number): number {
  return 30 + 200 * (1 - Math.exp(-waitSec / 120));
}
function premadeBonus(size: number): number { return 50 * Math.log2(Math.max(1, size)); }

export async function runMatchmakingTick(queue: string, region: string) {
  const entries = await loadQueue(queue, region);
  const parties = new Map<string, QueueEntry[]>();
  for (const e of entries) { if (!parties.has(e.partyId)) parties.set(e.partyId, []); parties.get(e.partyId)!.push(e); }
  const sortedParties = Array.from(parties.values()).sort((a, b) => Math.min(...a.map(x => x.enqueueMs)) - Math.min(...b.map(x => x.enqueueMs)));
  for (const seed of sortedParties) {
    const teamA = tryFillTeam([seed], sortedParties, 5);
    if (!teamA) continue;
    const teamB = tryFillTeam([], sortedParties.filter(p => !teamA.some(x => x.partyId === p[0].partyId)), 5);
    if (!teamB) continue;
    const avgA = teamA.reduce((s, p) => s + p.rating, 0) / 5 + premadeBonus(maxPartySize(teamA));
    const avgB = teamB.reduce((s, p) => s + p.rating, 0) / 5 + premadeBonus(maxPartySize(teamB));
    const gap = Math.abs(avgA - avgB);
    const oldestWait = (Date.now() - Math.min(...[...teamA, ...teamB].map(x => x.enqueueMs))) / 1000;
    if (gap > acceptableSkillGap(oldestWait)) continue;
    await commitMatch(queue, region, teamA, teamB);
    return true;
  }
  return false;
}

function tryFillTeam(seed: QueueEntry[][], pool: QueueEntry[][], target: number): QueueEntry[] | null {
  const out: QueueEntry[] = seed.flat();
  for (const party of pool) {
    if (party === seed[0]) continue;
    if (out.length + party.length <= target) out.push(...party);
    if (out.length === target) return out;
  }
  return null;
}
function maxPartySize(team: QueueEntry[]): number { const sizes: Record<string, number> = {}; for (const p of team) sizes[p.partyId] = (sizes[p.partyId] || 0) + 1; return Math.max(...Object.values(sizes)); }

async function commitMatch(queue: string, region: string, a: QueueEntry[], b: QueueEntry[]) {
  const matchId = await db.one('INSERT INTO matches(queue, team_a, team_b, team_a_avg_rating, team_b_avg_rating, started_at) VALUES ($1,$2,$3,$4,$5,NOW()) RETURNING id',
    [queue, JSON.stringify(a.map(p => p.playerId)), JSON.stringify(b.map(p => p.playerId)), avg(a), avg(b)]);
  for (const p of [...a, ...b]) await redis.zrem(`mm:queue:${queue}:${region}`, p.playerId);
  await notifyMatchFound(matchId.id, [...a, ...b]);
}
function avg(t: QueueEntry[]) { return t.reduce((s, p) => s + p.rating, 0) / t.length; }

// Smurf detection on each match
export async function flagSmurf(playerId: string) {
  const rating = await db.one('SELECT glicko_rating, glicko_deviation, games_played FROM player_rating WHERE player_id=$1', [playerId]);
  if (rating.games_played < 50 && rating.glicko_deviation < 100 && rating.glicko_rating > 1800) {
    await db.none('INSERT INTO smurf_review_queue(player_id, evidence) VALUES ($1, $2)', [playerId, JSON.stringify(rating)]);
  }
}

