// src/services/bracketBuilder.ts
import { db } from '../db';

export function snakeSeeding(seeds: number[]): Array<[number, number]> {
  const n = seeds.length;
  const pairs: Array<[number, number]> = [];
  for (let i = 0; i < n / 2; i++) pairs.push([seeds[i], seeds[n - 1 - i]]);
  return reorderSnake(pairs);
}
function reorderSnake(pairs: Array<[number, number]>): Array<[number, number]> {
  if (pairs.length <= 2) return pairs;
  const half = pairs.length / 2;
  const top = reorderSnake(pairs.slice(0, half));
  const bottom = reorderSnake(pairs.slice(half));
  const interleaved: Array<[number, number]> = [];
  for (let i = 0; i < half; i++) { interleaved.push(top[i]); interleaved.push(bottom[half - 1 - i]); }
  return interleaved;
}

export async function initializeSingleElimBracket(tournamentId: string, playerIds: string[]) {
  const seeded = playerIds.map((id, i) => ({ id, seed: i + 1 }));
  const r1Pairs = snakeSeeding(seeded.map(s => s.seed));
  return db.tx(async tx => {
    const rounds = Math.log2(playerIds.length);
    const matchesByRound: any[][] = [];
    for (let r = 0; r < rounds; r++) {
      const n = playerIds.length / Math.pow(2, r + 1);
      matchesByRound[r] = [];
      for (let i = 0; i < n; i++) matchesByRound[r].push({ round: r, slot: i, id: null });
    }
    for (let r = rounds - 1; r >= 0; r--) {
      for (const m of matchesByRound[r]) {
        const nextMatch = r > 0 ? matchesByRound[r - 1].find(x => x.slot === Math.floor(m.slot / 2)) : null;
        const row = await tx.one('INSERT INTO tournament_matches(tournament_id, round, bracket, slot_index, advances_to_match_id) VALUES ($1,$2,0,$3,$4) RETURNING id', [tournamentId, r, m.slot, nextMatch?.id || null]);
        m.id = row.id;
      }
    }
    const firstRound = matchesByRound[rounds - 1];
    for (let i = 0; i < r1Pairs.length; i++) {
      const [seedA, seedB] = r1Pairs[i];
      const playerA = seeded.find(s => s.seed === seedA)!.id;
      const playerB = seeded.find(s => s.seed === seedB)!.id;
      await tx.none('UPDATE tournament_matches SET player_a=$1, player_b=$2 WHERE id=$3', [playerA, playerB, firstRound[i].id]);
    }
  });
}

// src/services/matchAdvancement.ts
import { redis } from '../redis';
import { io } from '../socket';
export async function reportMatchResult(matchId: string, winner: string, scoreA: number, scoreB: number, signature: string) {
  if (!verifyMatchSignature(matchId, winner, scoreA, scoreB, signature)) throw new Error('invalid_signature');
  return db.tx(async tx => {
    const m = await tx.one('SELECT * FROM tournament_matches WHERE id=$1 FOR UPDATE', [matchId]);
    if (m.winner) throw new Error('already_reported');
    if (winner !== m.player_a && winner !== m.player_b) throw new Error('invalid_winner');
    await tx.none('UPDATE tournament_matches SET winner=$1, score_a=$2, score_b=$3, ended_at=NOW() WHERE id=$4', [winner, scoreA, scoreB, matchId]);
    if (m.advances_to_match_id) {
      const next = await tx.one('SELECT * FROM tournament_matches WHERE id=$1 FOR UPDATE', [m.advances_to_match_id]);
      const targetSlot = m.slot_index % 2 === 0 ? 'player_a' : 'player_b';
      if (next[targetSlot]) throw new Error('next_slot_filled');
      await tx.none(`UPDATE tournament_matches SET ${targetSlot}=$1 WHERE id=$2`, [winner, m.advances_to_match_id]);
    } else {
      await finalizeAndDistribute(tx, m.tournament_id, winner);
    }
    await redis.del(`bracket:${m.tournament_id}`);
    io.to(`tournament:${m.tournament_id}`).emit('bracket_update', { matchId, winner, scoreA, scoreB });
  });
}

async function finalizeAndDistribute(tx: any, tournamentId: string, championId: string) {
  const tournament = await tx.one('SELECT * FROM tournaments WHERE id=$1', [tournamentId]);
  const positions = await computeFinalPositions(tx, tournamentId);
  for (const [pos, playerId] of positions.entries()) {
    const sharePct = tournament.prize_distribution[pos + 1] || 0;
    const prizeUsd = tournament.prize_pool_usd * sharePct;
    if (prizeUsd > 0) await tx.none('INSERT INTO prize_payouts(tournament_id, position, player_id, amount_usd, idempotency_key) VALUES ($1,$2,$3,$4,$5) ON CONFLICT (idempotency_key) DO NOTHING', [tournamentId, pos + 1, playerId, prizeUsd, `${tournamentId}:${pos + 1}`]);
    await tx.none('UPDATE tournament_players SET final_position=$1 WHERE tournament_id=$2 AND player_id=$3', [pos + 1, tournamentId, playerId]);
  }
  await tx.none('UPDATE tournaments SET status=$1, completed_at=NOW() WHERE id=$2', ['completed', tournamentId]);
}

// src/services/swissPairing.ts
export async function generateSwissPairings(tournamentId: string, round: number) {
  const players = await db.any('SELECT player_id, score, opponents_played FROM tournament_players WHERE tournament_id=$1 ORDER BY score DESC, seed ASC', [tournamentId]);
  const groups: Record<string, any[]> = {};
  for (const p of players) (groups[p.score] ??= []).push(p);
  const pairings: Array<[string, string]> = [];
  let carry: any[] = [];
  for (const score of Object.keys(groups).sort((a, b) => Number(b) - Number(a))) {
    const pool = [...carry, ...groups[score]];
    carry = [];
    while (pool.length >= 2) {
      const a = pool.shift()!;
      const bIdx = pool.findIndex(p => !a.opponents_played.includes(p.player_id));
      if (bIdx === -1) { carry.push(a); continue; }
      const b = pool.splice(bIdx, 1)[0];
      pairings.push([a.player_id, b.player_id]);
    }
    carry.push(...pool);
  }
  if (carry.length === 1) { await db.none('UPDATE tournament_players SET score = score + 1, byes = byes + 1 WHERE tournament_id=$1 AND player_id=$2', [tournamentId, carry[0].player_id]); }
  return pairings;
}

