import { db } from '../db';
import { pushNotification } from './notificationService';
import { applyCurrencyChange } from './economyService';

export async function grantXp(playerId: string, seasonId: string, amount: number, source: string, idempotencyKey: string) {
  return db.tx(async tx => {
    const dup = await tx.oneOrNone('SELECT 1 FROM xp_grants_log WHERE idempotency_key=$1', [idempotencyKey]);
    if (dup) return { duplicate: true };
    const season = await tx.one('SELECT * FROM seasons WHERE id=$1', [seasonId]);
    const daysLeft = Math.max(0, (new Date(season.ends_at).getTime() - Date.now()) / 86400000);
    const multiplier = daysLeft <= 14 ? 1 + (14 - daysLeft) / 14 * 0.5 : 1;
    const adjusted = Math.floor(amount * multiplier);
    const bp = await tx.one('SELECT * FROM player_battle_pass WHERE player_id=$1 AND season_id=$2 FOR UPDATE', [playerId, seasonId]);
    let totalXp = bp.current_xp + adjusted;
    let newTier = bp.current_tier;
    const tierCrossings: number[] = [];
    while (totalXp >= season.xp_per_tier && newTier < season.max_tier) { totalXp -= season.xp_per_tier; newTier += 1; tierCrossings.push(newTier); }
    if (newTier === season.max_tier) totalXp = 0;
    await tx.none('INSERT INTO xp_grants_log(player_id, season_id, source, amount, multiplier, idempotency_key) VALUES ($1,$2,$3,$4,$5,$6)', [playerId, seasonId, source, amount, multiplier, idempotencyKey]);
    await tx.none('UPDATE player_battle_pass SET current_xp=$1, current_tier=$2, last_xp_at=NOW() WHERE player_id=$3 AND season_id=$4', [totalXp, newTier, playerId, seasonId]);
    for (const tier of tierCrossings) await grantTierRewards(tx, playerId, seasonId, tier, bp.premium_active);
    return { newTier, newXp: totalXp, multiplier, tierCrossings };
  });
}

async function grantTierRewards(tx: any, playerId: string, seasonId: string, tier: number, premium: boolean) {
  const freeReward = await tx.oneOrNone('SELECT * FROM battle_pass_rewards WHERE season_id=$1 AND tier=$2 AND track=$3', [seasonId, tier, 'free']);
  if (freeReward) await applyReward(tx, playerId, freeReward.reward_payload, `bp:${seasonId}:t${tier}:free`);
  if (premium) {
    const premReward = await tx.oneOrNone('SELECT * FROM battle_pass_rewards WHERE season_id=$1 AND tier=$2 AND track=$3', [seasonId, tier, 'premium']);
    if (premReward) await applyReward(tx, playerId, premReward.reward_payload, `bp:${seasonId}:t${tier}:prem`);
  }
  await tx.none(`UPDATE player_battle_pass SET tiers_claimed = tiers_claimed || $1::jsonb WHERE player_id=$2 AND season_id=$3`, [JSON.stringify([{ tier, claimed_at: new Date() }]), playerId, seasonId]);
  await pushNotification(playerId, { type: 'battle_pass_tier', urgency: 'high', payload: { tier, premium } });
}

async function applyReward(tx: any, playerId: string, payload: any, idemKey: string) {
  if (payload.type === 'currency') await applyCurrencyChange({ playerId, currency: payload.currency, delta: payload.amount, reason: 'battle_pass', referenceId: idemKey, idempotencyKey: idemKey });
  else if (payload.type === 'cosmetic') await tx.none('INSERT INTO player_cosmetics(player_id, cosmetic_code, acquired_at) VALUES ($1,$2,NOW()) ON CONFLICT DO NOTHING', [playerId, payload.code]);
}

export async function purchasePremium(playerId: string, seasonId: string, receiptValid: boolean) {
  if (!receiptValid) throw new Error('invalid_purchase');
  return db.tx(async tx => {
    const bp = await tx.one('SELECT * FROM player_battle_pass WHERE player_id=$1 AND season_id=$2 FOR UPDATE', [playerId, seasonId]);
    if (bp.premium_active) return { alreadyPremium: true };
    await tx.none('UPDATE player_battle_pass SET premium_active=true, premium_purchased_at=NOW() WHERE player_id=$1 AND season_id=$2', [playerId, seasonId]);
    for (let t = 1; t <= bp.current_tier; t++) {
      const premReward = await tx.oneOrNone('SELECT * FROM battle_pass_rewards WHERE season_id=$1 AND tier=$2 AND track=$3', [seasonId, t, 'premium']);
      if (premReward) await applyReward(tx, playerId, premReward.reward_payload, `bp:${seasonId}:t${t}:prem:retro`);
    }
    return { granted: bp.current_tier };
  });
}

