// src/services/matchEngine.ts
import { redis } from '../redis';
import { io } from '../socket';
import crypto from 'crypto';
import { mulberry32 } from '../lib/prng';

export interface GameState {
  matchId: string;
  players: { id: string; hp: number; mana: number; hand: any[]; deck: any[] }[];
  turn: number;
  currentPlayer: 0 | 1;
  turnStartedAt: number;
  clocks: [number, number];
  prngSeed: number;
  prngCounter: number;
  ended: boolean;
  winner: string | null;
}

function stateHash(s: GameState): string {
  const canonical = JSON.stringify({ turn: s.turn, players: s.players, currentPlayer: s.currentPlayer, ended: s.ended });
  return crypto.createHash('sha256').update(canonical).digest('hex').slice(0, 16);
}

function nextRand(s: GameState): number {
  s.prngCounter += 1;
  return mulberry32(s.prngSeed + s.prngCounter)();
}

export async function loadState(matchId: string): Promise<GameState | null> {
  const json = await redis.get(`match:${matchId}:state`);
  return json ? JSON.parse(json) : null;
}
export async function saveState(s: GameState) {
  await redis.set(`match:${s.matchId}:state`, JSON.stringify(s), 'EX', 3600);
}

export async function applyAction(matchId: string, playerId: string, action: any) {
  const state = await loadState(matchId);
  if (!state) throw new Error('match_not_found');
  if (state.ended) throw new Error('match_ended');
  const playerIdx = state.players.findIndex(p => p.id === playerId);
  if (playerIdx === -1) throw new Error('not_in_match');
  if (playerIdx !== state.currentPlayer) throw new Error('not_your_turn');
  const elapsed = Date.now() - state.turnStartedAt;
  state.clocks[playerIdx] -= elapsed;
  if (state.clocks[playerIdx] <= 0) { return endMatchByTimeout(state); }
  switch (action.type) {
    case 'play_card': await applyPlayCard(state, playerIdx, action); break;
    case 'attack': await applyAttack(state, playerIdx, action); break;
    case 'end_turn': applyEndTurn(state); break;
    default: throw new Error('unknown_action');
  }
  state.clocks[playerIdx] += 5000;
  state.turnStartedAt = Date.now();
  await redis.rpush(`match:${matchId}:actions`, JSON.stringify({ ...action, playerId, ts: Date.now() }));
  await saveState(state);
  const hash = stateHash(state);
  io.to(`match:${matchId}`).emit('state_delta', { action, state, hash });
  if (state.ended) await archiveMatch(state);
  return { state, hash };
}

async function applyPlayCard(state: GameState, playerIdx: number, action: any) {
  const p = state.players[playerIdx];
  const cardIdx = p.hand.findIndex(c => c.instanceId === action.cardInstanceId);
  if (cardIdx === -1) throw new Error('card_not_in_hand');
  const card = p.hand[cardIdx];
  if (card.cost > p.mana) throw new Error('insufficient_mana');
  p.mana -= card.cost;
  p.hand.splice(cardIdx, 1);
  if (card.effect === 'damage') state.players[1 - playerIdx].hp -= card.damage;
  if (state.players[1 - playerIdx].hp <= 0) { state.ended = true; state.winner = p.id; }
}
async function applyAttack(state: GameState, playerIdx: number, action: any) { /* ... */ }
function applyEndTurn(state: GameState) {
  state.currentPlayer = state.currentPlayer === 0 ? 1 : 0;
  state.turn += 1;
  state.players[state.currentPlayer].mana = Math.min(10, state.turn);
  const draw = state.players[state.currentPlayer].deck.shift();
  if (draw) state.players[state.currentPlayer].hand.push(draw);
}
function endMatchByTimeout(state: GameState) { state.ended = true; state.winner = state.players[1 - state.currentPlayer].id; return { state, hash: stateHash(state), timedOut: true }; }
async function archiveMatch(state: GameState) { /* persist to Postgres */ }

// src/socket/matchHandlers.ts
import { Server, Socket } from 'socket.io';
import { applyAction, loadState } from '../services/matchEngine';
export function registerMatchHandlers(io: Server) {
  io.on('connection', (socket: Socket) => {
    socket.on('match:join', async (matchId: string) => {
      socket.join(`match:${matchId}`);
      const state = await loadState(matchId);
      socket.emit('state_full', state);
    });
    socket.on('match:action', async (data: any, ack) => {
      try { const result = await applyAction(data.matchId, data.playerId, data.action); ack({ ok: true, hash: result.hash }); }
      catch (e: any) { ack({ ok: false, error: e.message }); const state = await loadState(data.matchId); socket.emit('state_full', state); }
    });
    socket.on('disconnect', () => { /* mark player disconnected, start 30s grace timer */ });
  });
}

