    const state: GameState = JSON.parse((await redis.get(key))!);
    if (state.ended) continue;
    const elapsed = Date.now() - state.turnStartedAt;
    if (state.clocks[state.currentPlayer] - elapsed <= 0) {
      state.clocks[state.currentPlayer] = 0;
      const result = endMatchByTimeout(state);
      await saveState(state);
