// src/hooks/useMatchState.ts
import { useEffect, useState, useRef } from 'react';
import { useSocket } from './useSocket';
import crypto from 'crypto-browserify';
function stateHash(s: any): string { const canonical = JSON.stringify({ turn: s.turn, players: s.players, currentPlayer: s.currentPlayer, ended: s.ended }); return crypto.createHash('sha256').update(canonical).digest('hex').slice(0, 16); }
export function useMatchState(matchId: string, playerId: string) {
  const socket = useSocket();
  const [state, setState] = useState<any>(null);
  const [predicted, setPredicted] = useState<any>(null);
  const [connectionState, setConnectionState] = useState<'connected' | 'reconnecting'>('connected');
  useEffect(() => {
    socket.emit('match:join', matchId);
    socket.on('state_full', (s: any) => { setState(s); setPredicted(null); });
    socket.on('state_delta', (msg: any) => {
      const localHash = stateHash(msg.state);
      if (localHash !== msg.hash) { console.warn('desync detected, requesting full state'); socket.emit('match:resync', matchId); return; }
      setState(msg.state); setPredicted(null);
    });
    socket.on('disconnect', () => setConnectionState('reconnecting'));
    socket.on('connect', () => { setConnectionState('connected'); if (matchId) socket.emit('match:join', matchId); });
    return () => { socket.off('state_full'); socket.off('state_delta'); };
  }, [matchId, socket]);
  const sendAction = (action: any) => {
    const optimistic = optimisticApply(state, playerId, action);
    setPredicted(optimistic);
    socket.emit('match:action', { matchId, playerId, action }, (ack: any) => {
      if (!ack.ok) setPredicted(null);
    });
  };
  return { state: predicted || state, sendAction, connectionState };
}
function optimisticApply(state: any, playerId: string, action: any): any {
  if (!state || action.type !== 'play_card') return state;
  const next = JSON.parse(JSON.stringify(state));
  const idx = next.players.findIndex((p: any) => p.id === playerId);
  const card = next.players[idx].hand.find((c: any) => c.instanceId === action.cardInstanceId);
  if (!card || card.cost > next.players[idx].mana) return state;
  next.players[idx].mana -= card.cost;
  next.players[idx].hand = next.players[idx].hand.filter((c: any) => c.instanceId !== action.cardInstanceId);
  return next;
}

