// src/lib/xorshift.ts
export function xorshift128plus(seed: bigint) {
  let s0 = seed; let s1 = seed * 0x9E3779B97F4A7C15n;
  return function() {
    let x = s0; const y = s1; s0 = y;
    x ^= x << 23n; x &= 0xFFFFFFFFFFFFFFFFn;
    s1 = x ^ y ^ (x >> 17n) ^ (y >> 26n);
    return Number((s1 + y) & 0xFFFFFFFFn) / 0x100000000;
  };
}

// src/services/mapGenerator.ts
import { xorshift128plus } from '../lib/xorshift';

export interface MapNode { id: string; floor: number; col: number; roomType: string; }
export interface DungeonMap { nodes: MapNode[]; edges: Array<[string, string]>; seed: string; }

const FLOORS = 15;
const COLS = 7;
const ROOM_WEIGHTS: Record<number, Record<string, number>> = {
  1: { combat: 6, treasure: 1, event: 2 },
  5: { combat: 5, elite: 1, treasure: 1, event: 2, rest: 1 },
  10: { combat: 4, elite: 2, treasure: 1, event: 2, rest: 1, shop: 0.5 },
  14: { combat: 3, elite: 3, treasure: 1, rest: 1, shop: 0.5 },
  15: { boss: 1 }
};

function weightsForFloor(floor: number): Record<string, number> {
  const keys = Object.keys(ROOM_WEIGHTS).map(Number).sort((a, b) => a - b);
  let closest = keys[0];
  for (const k of keys) if (k <= floor) closest = k;
  return ROOM_WEIGHTS[closest];
}
function pickWeighted(weights: Record<string, number>, rand: () => number): string {
  const total = Object.values(weights).reduce((a, b) => a + b, 0);
  let r = rand() * total;
  for (const [k, w] of Object.entries(weights)) { r -= w; if (r <= 0) return k; }
  return Object.keys(weights)[0];
}

export function generateMap(seedHex: string): DungeonMap {
  const seed = BigInt('0x' + seedHex);
  const rand = xorshift128plus(seed);
  const nodes: MapNode[] = [];
  const edges: Array<[string, string]> = [];
  for (let f = 0; f < FLOORS; f++) {
    const colCount = f === FLOORS - 1 ? 1 : 2 + Math.floor(rand() * (COLS - 2));
    for (let c = 0; c < colCount; c++) {
      const w = weightsForFloor(f + 1);
      let rt = pickWeighted(w, rand);
      if (rt === 'elite' && nodes.some(n => n.floor === f - 1 && n.roomType === 'elite')) rt = 'combat';
      nodes.push({ id: `f${f}c${c}`, floor: f, col: c, roomType: rt });
    }
  }
  for (let f = 0; f < FLOORS - 1; f++) {
    const here = nodes.filter(n => n.floor === f);
    const next = nodes.filter(n => n.floor === f + 1);
    for (const n of here) {
      const branchCount = 1 + Math.floor(rand() * Math.min(3, next.length));
      const targets = [...next].sort(() => rand() - 0.5).slice(0, branchCount);
      for (const t of targets) edges.push([n.id, t.id]);
    }
    for (const t of next) { if (!edges.some(e => e[1] === t.id)) edges.push([here[Math.floor(rand() * here.length)].id, t.id]); }
  }
  return { nodes, edges, seed: seedHex };
}

// src/services/lootNaming.ts
const ADJECTIVES = [{ word: 'Ancient', rarity: 2 }, { word: 'Cursed', rarity: 3 }, { word: 'Worn', rarity: 0 }, /* ... 50 entries */];
const MATERIALS = [{ word: 'Iron', rarity: 0 }, { word: 'Obsidian', rarity: 2 }, /* ... */];
const WEAPONS = [{ word: 'Sword', kind: 'sword' }, { word: 'Hammer', kind: 'hammer' }];
const SUFFIX_POWERS = [{ word: 'Burning', element: 'fire', rarity: 1 }, { word: 'Annihilation', rarity: 3 }];

export function generateLootName(rand: () => number): { name: string; rarity: number; element?: string } {
  function pickWeightedRarity<T extends { rarity: number }>(arr: T[]): T {
    return arr[Math.floor(rand() * arr.length)];
  }
  const adj = pickWeightedRarity(ADJECTIVES);
  const mat = pickWeightedRarity(MATERIALS);
  const wpn = WEAPONS[Math.floor(rand() * WEAPONS.length)];
  const useSuffix = rand() < 0.6;
  const suffix = useSuffix ? pickWeightedRarity(SUFFIX_POWERS) : null;
  const rarityScore = adj.rarity + mat.rarity + (suffix?.rarity || 0);
  const rarity = rarityScore >= 6 ? 4 : rarityScore >= 4 ? 3 : rarityScore >= 2 ? 2 : 1;
  const name = suffix ? `${adj.word} ${mat.word} ${wpn.word} of ${suffix.word}` : `${adj.word} ${mat.word} ${wpn.word}`;
  return { name, rarity, element: (suffix as any)?.element };
}

// src/services/dialogueMarkov.ts
import { db } from '../db';
export async function generateDialogue(seed: string, length = 20): Promise<string> {
  const rand = xorshift128plus(BigInt('0x' + seed));
  const starters = await db.any(`SELECT prev_word_pair FROM dialogue_markov WHERE prev_word_pair LIKE '<START>%' ORDER BY random_seed(${seed}) LIMIT 1`);
  let pair = starters[0]?.prev_word_pair.split(' ') || ['<START>', 'I'];
  const out: string[] = [pair[1]];
  for (let i = 0; i < length; i++) {
    const candidates = await db.any('SELECT next_word, count FROM dialogue_markov WHERE prev_word_pair=$1', [pair.join(' ')]);
    if (candidates.length === 0) break;
    const total = candidates.reduce((s, c) => s + c.count, 0);
    let r = rand() * total;
    let next = '';
    for (const c of candidates) { r -= c.count; if (r <= 0) { next = c.next_word; break; } }
    if (next === '<END>') break;
    out.push(next);
    pair = [pair[1], next];
  }
  return out.join(' ');
}

