// src/components/Card3D.tsx
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { useRef, useState, useMemo, Suspense } from 'react';
import { useTexture, Plane } from '@react-three/drei';
import * as THREE from 'three';

const foilShader = {
  uniforms: { uTexture: { value: null }, uTime: { value: 0 }, uFoilSeed: { value: 0 }, uRarity: { value: 1 } },
  vertexShader: `
    varying vec2 vUv; varying vec3 vNormal; varying vec3 vViewDir;
    void main() {
      vUv = uv; vNormal = normalize(normalMatrix * normal);
      vec4 mv = modelViewMatrix * vec4(position, 1.0);
      vViewDir = normalize(-mv.xyz);
      gl_Position = projectionMatrix * mv;
    }`,
  fragmentShader: `
    varying vec2 vUv; varying vec3 vNormal; varying vec3 vViewDir;
    uniform sampler2D uTexture; uniform float uTime; uniform float uFoilSeed; uniform float uRarity;
    vec3 hueShift(vec3 c, float h) {
      const mat3 m1 = mat3(0.299,0.587,0.114, 0.299,0.587,0.114, 0.299,0.587,0.114);
      const mat3 m2 = mat3(0.701,-0.587,-0.114, -0.299,0.413,-0.114, -0.300,-0.588,0.886);
      const mat3 m3 = mat3(0.168,0.330,-0.497, -0.328,0.035,0.292, 1.250,-0.065,-0.203);
      float cosA = cos(h * 6.28318); float sinA = sin(h * 6.28318);
      return c * m1 + c * m2 * cosA + c * m3 * sinA;
    }
    void main() {
      vec4 base = texture2D(uTexture, vUv);
      float view = dot(normalize(vNormal), normalize(vViewDir));
      float pattern = sin((vUv.x + vUv.y) * 40.0 + view * 10.0 + uFoilSeed) * 0.5 + 0.5;
      float shimmer = pow(pattern, 3.0);
      vec3 foil = hueShift(vec3(1.0, 0.5, 1.0), pattern + uTime * 0.1);
      vec3 color = mix(base.rgb, base.rgb + foil * shimmer, uRarity * 0.4);
      gl_FragColor = vec4(color, base.a);
    }`
};

function CardMesh({ card, revealed, onComplete }: any) {
  const meshRef = useRef<THREE.Mesh>(null);
  const texture = useTexture(card.art_url);
  const backTexture = useTexture('/textures/card_back.png');
  const { mouse } = useThree();
  const material = useMemo(() => new THREE.ShaderMaterial({ ...foilShader, uniforms: { uTexture: { value: texture }, uTime: { value: 0 }, uFoilSeed: { value: parseFloat(card.foil_seed) % 100 }, uRarity: { value: card.rarity } } }), [texture, card]);
  const [rotation, setRotation] = useState(Math.PI);
  useFrame((state, delta) => {
    if (!meshRef.current) return;
    material.uniforms.uTime.value += delta;
    if (revealed && rotation > 0) {
      const next = Math.max(0, rotation - delta * 4);
      setRotation(next);
      meshRef.current.rotation.y = next;
      if (next === 0 && onComplete) onComplete();
    } else {
      meshRef.current.rotation.y += (mouse.x * 0.3 - meshRef.current.rotation.y) * 0.1;
      meshRef.current.rotation.x += (-mouse.y * 0.2 - meshRef.current.rotation.x) * 0.1;
    }
  });
  return (
    <mesh ref={meshRef}>
      <planeGeometry args={[1.5, 2.1]} />
      <primitive attach='material' object={material} />
      <mesh position={[0, 0, -0.01]} rotation={[0, Math.PI, 0]}>
        <planeGeometry args={[1.5, 2.1]} />
        <meshBasicMaterial map={backTexture} />
      </mesh>
    </mesh>
  );
}

function LegendaryBurst({ active }: { active: boolean }) {
  const ref = useRef<THREE.InstancedMesh>(null);
  const count = 200;
  const data = useMemo(() => Array.from({ length: count }, (_, i) => {
    const phi = (1 + Math.sqrt(5)) / 2;
    const theta = i * phi * 2 * Math.PI;
    const r = Math.random() * 2 + 0.5;
    return { vx: Math.cos(theta) * r, vy: Math.sin(theta) * r, vz: (Math.random() - 0.5) * r };
  }), []);
  useFrame((state, delta) => {
    if (!ref.current || !active) return;
    const matrix = new THREE.Matrix4();
    const t = state.clock.elapsedTime;
    for (let i = 0; i < count; i++) {
      const d = data[i];
      matrix.makeTranslation(d.vx * t * 0.5, d.vy * t * 0.5, d.vz * t * 0.5);
      ref.current.setMatrixAt(i, matrix);
    }
    ref.current.instanceMatrix.needsUpdate = true;
  });
  if (!active) return null;
  return (
    <instancedMesh ref={ref} args={[undefined as any, undefined as any, count]}>
      <sphereGeometry args={[0.02, 8, 8]} />
      <meshBasicMaterial color='#facc15' />
    </instancedMesh>
  );
}

export function Card3DReveal({ card }: any) {
  const [revealed, setRevealed] = useState(false);
  const [burstActive, setBurstActive] = useState(false);
  return (
    <div className='w-full h-96 bg-gradient-to-b from-slate-950 to-slate-900' onClick={() => setRevealed(true)}>
      <Canvas camera={{ position: [0, 0, 3.5] }}>
        <ambientLight intensity={0.5} />
        <pointLight position={[2, 2, 2]} intensity={1.5} />
        <Suspense fallback={null}>
          <CardMesh card={card} revealed={revealed} onComplete={() => card.rarity >= 4 && setBurstActive(true)} />
          <LegendaryBurst active={burstActive} />
        </Suspense>
      </Canvas>
    </div>
  );
}

