// src/services/guildService.ts
import { db } from '../db';
import { io } from '../socket';

export async function createGuild(creatorId: string, name: string, tag: string) {
  return db.tx(async tx => {
    const existing = await tx.oneOrNone('SELECT 1 FROM guild_members WHERE player_id=$1', [creatorId]);
    if (existing) throw new Error('already_in_guild');
    await tx.none('UPDATE players SET premium_currency = premium_currency - 500 WHERE id=$1 AND premium_currency >= 500', [creatorId]);
    const guild = await tx.one('INSERT INTO guilds(name, tag, level, member_cap, created_by) VALUES ($1,$2,1,30,$3) RETURNING *', [name, tag, creatorId]);
    await tx.none('INSERT INTO guild_members(guild_id, player_id, role) VALUES ($1,$2,$3)', [guild.id, creatorId, 'leader']);
    return guild;
  });
}

export async function contributeToQuest(playerId: string, questId: string, amount: number) {
  return db.tx(async tx => {
    const quest = await tx.one('SELECT * FROM guild_quests WHERE id=$1 FOR UPDATE', [questId]);
    if (quest.status !== 'active') throw new Error('quest_not_active');
    const member = await tx.one('SELECT * FROM guild_members WHERE guild_id=$1 AND player_id=$2', [quest.guild_id, playerId]);
    const existingContrib = await tx.oneOrNone('SELECT contribution FROM guild_quest_contributions WHERE quest_id=$1 AND player_id=$2', [questId, playerId]);
    const cap = quest.target * 0.25;
    const allowed = Math.min(amount, cap - (existingContrib?.contribution || 0));
    if (allowed <= 0) return { capped: true };
    await tx.none('INSERT INTO guild_quest_contributions(quest_id, player_id, contribution) VALUES ($1,$2,$3) ON CONFLICT (quest_id, player_id) DO UPDATE SET contribution = guild_quest_contributions.contribution + $3', [questId, playerId, allowed]);
    const newProgress = quest.progress + allowed;
    await tx.none('UPDATE guild_quests SET progress=$1 WHERE id=$2', [Math.min(newProgress, quest.target), questId]);
    await tx.none('UPDATE guild_members SET last_contribution_at=NOW(), total_contribution = total_contribution + $1 WHERE guild_id=$2 AND player_id=$3', [allowed, quest.guild_id, playerId]);
    const memberCount = await tx.one('SELECT COUNT(*) FROM guild_members WHERE guild_id=$1 AND role != $2', [quest.guild_id, 'applicant']);
    const modifier = 1 / Math.log2(2 + Number(memberCount.count));
    const guildXp = Math.floor(allowed * modifier);
    await tx.none('UPDATE guilds SET xp = xp + $1 WHERE id=$2', [guildXp, quest.guild_id]);
    if (newProgress >= quest.target) {
      await tx.none('UPDATE guild_quests SET status=$1 WHERE id=$2', ['completed', questId]);
      io.to(`guild:${quest.guild_id}`).emit('guild_quest_completed', { questId });
    }
    io.to(`guild:${quest.guild_id}`).emit('quest_progress', { questId, progress: newProgress, target: quest.target, by: playerId });
    return { contributed: allowed, newTotal: newProgress };
  });
}

export async function postMessage(playerId: string, guildId: string, content: string) {
  const filtered = await profanityFilter(content);
  const recentCount = await db.one('SELECT COUNT(*) FROM guild_chat_messages WHERE sender_id=$1 AND created_at > NOW() - INTERVAL '1 minute'', [playerId]);
  const baseRate = 10;
  const allowed = baseRate / (1 + Number(recentCount.count) / 5);
  if (allowed < 1) throw new Error('rate_limited');
  const msg = await db.one('INSERT INTO guild_chat_messages(guild_id, sender_id, content) VALUES ($1,$2,$3) RETURNING *', [guildId, playerId, filtered.content]);
  io.to(`guild:${guildId}`).emit('chat_message', msg);
  return msg;
}

export async function reportMessage(reporterId: string, messageId: string, reason: string) {
  const msg = await db.one('SELECT * FROM guild_chat_messages WHERE id=$1', [messageId]);
  await db.none('INSERT INTO guild_moderation_reports(guild_id, reporter_id, target_id, message_id, reason) VALUES ($1,$2,$3,$4,$5) ON CONFLICT DO NOTHING', [msg.guild_id, reporterId, msg.sender_id, messageId, reason]);
  const uniqueReports = await db.one('SELECT COUNT(DISTINCT reporter_id) FROM guild_moderation_reports WHERE target_id=$1 AND created_at > NOW() - INTERVAL '24 hours'', [msg.sender_id]);
  if (Number(uniqueReports.count) >= 3) await applyAutoMute(msg.sender_id, msg.guild_id);
}
async function applyAutoMute(playerId: string, guildId: string) {
  await db.none('INSERT INTO guild_moderation_actions(guild_id, target_id, action, expires_at, reason) VALUES ($1,$2,$3,NOW()+INTERVAL '24 hours',$4)', [guildId, playerId, 'mute', 'auto: 3+ unique reports']);
}

// src/jobs/leaderSuccession.ts — runs daily
import { Worker } from 'bullmq';
new Worker('leader-succession', async () => {
  const stale = await db.any(`SELECT g.id, gm.player_id FROM guilds g JOIN guild_members gm ON g.id=gm.guild_id AND gm.role='leader' WHERE gm.last_contribution_at < NOW() - INTERVAL '14 days'`);
  for (const s of stale) {
    const successor = await db.oneOrNone('SELECT player_id FROM guild_members WHERE guild_id=$1 AND role=$2 ORDER BY total_contribution DESC LIMIT 1', [s.id, 'officer']);
    if (successor) {
      await db.tx(async tx => {
        await tx.none('UPDATE guild_members SET role=$1 WHERE guild_id=$2 AND player_id=$3', ['member', s.id, s.player_id]);
        await tx.none('UPDATE guild_members SET role=$1 WHERE guild_id=$2 AND player_id=$3', ['leader', s.id, successor.player_id]);
      });
      io.to(`guild:${s.id}`).emit('leader_changed', { newLeader: successor.player_id, reason: 'auto-succession' });
    }
  }
});

