// src/services/antiCheatAnalyzer.ts
import { db } from '../db';
import { redis } from '../redis';

function ksTest(sample: number[], baselineCdf: (x: number) => number): number {
  const sorted = [...sample].sort((a, b) => a - b);
  let maxD = 0;
  for (let i = 0; i < sorted.length; i++) {
    const empirical = (i + 1) / sorted.length;
    const theoretical = baselineCdf(sorted[i]);
    maxD = Math.max(maxD, Math.abs(empirical - theoretical));
  }
  return maxD;
}

function humanAimAngleCdf(angle: number): number {
  const mean = 4.5; const std = 2.5;
  return 0.5 * (1 + erf((angle - mean) / (std * Math.SQRT2)));
}
function erf(x: number): number {
  const t = 1 / (1 + 0.3275911 * Math.abs(x));
  const y = 1 - (((((1.061405429 * t - 1.453152027) * t) + 1.421413741) * t - 0.284496736) * t + 0.254829592) * t * Math.exp(-x * x);
  return x >= 0 ? y : -y;
}

export async function analyzeMatch(matchId: string) {
  const players = await db.any('SELECT DISTINCT player_id FROM player_telemetry WHERE match_id=$1', [matchId]);
  for (const p of players) {
    const aimAngles = await db.any(`SELECT (payload->>'angle')::numeric AS angle FROM player_telemetry WHERE match_id=$1 AND player_id=$2 AND action_type='shot_hit'`, [matchId, p.player_id]);
    if (aimAngles.length >= 20) {
      const angles = aimAngles.map(r => Number(r.angle));
      const ksD = ksTest(angles, humanAimAngleCdf);
      await db.none('INSERT INTO anti_cheat_scores(player_id, match_id, signal_type, value) VALUES ($1,$2,$3,$4)', [p.player_id, matchId, 'aim_distribution', ksD]);
      if (ksD > 0.5) await flagForReview(p.player_id, 'aim_distribution', ksD, { angles });
    }
    const preAimEvents = await db.any(`SELECT COUNT(*) FILTER (WHERE (payload->>'pre_aimed')::boolean = true) AS pre_aimed, COUNT(*) AS total FROM player_telemetry WHERE match_id=$1 AND player_id=$2 AND action_type='enemy_visible'`, [matchId, p.player_id]);
    if (Number(preAimEvents[0].total) >= 30) {
      const rate = Number(preAimEvents[0].pre_aimed) / Number(preAimEvents[0].total);
      await db.none('INSERT INTO anti_cheat_scores(player_id, match_id, signal_type, value) VALUES ($1,$2,$3,$4)', [p.player_id, matchId, 'pre_aim_rate', rate]);
      if (rate > 0.4) await flagForReview(p.player_id, 'wallhack_suspect', rate, { rate });
    }
  }
  const compositeScores = await db.any(`SELECT player_id, SUM(CASE signal_type WHEN 'aim_distribution' THEN value * 2 WHEN 'pre_aim_rate' THEN value * 3 ELSE 0 END) AS composite FROM anti_cheat_scores WHERE match_id=$1 GROUP BY player_id`, [matchId]);
  for (const c of compositeScores) {
    if (Number(c.composite) > 1.5) await applyShadowBan(c.player_id, 'composite_suspicion', { composite: c.composite });
  }
}

async function flagForReview(playerId: string, signal: string, value: number, evidence: any) {
  await db.none('INSERT INTO manual_review_queue(player_id, signal, value, evidence) VALUES ($1,$2,$3,$4)', [playerId, signal, value, evidence]);
}

export async function applyShadowBan(playerId: string, reason: string, evidence: any) {
  await db.none('INSERT INTO ban_records(player_id, type, reason, evidence) VALUES ($1,$2,$3,$4)', [playerId, 'shadow', reason, evidence]);
  await redis.sadd('shadow_banned', playerId);
}

export async function isShadowBanned(playerId: string): Promise<boolean> {
  return (await redis.sismember('shadow_banned', playerId)) === 1;
}

// src/services/behavioralFingerprint.ts
function cosineSim(a: number[], b: number[]): number {
  let dot = 0, na = 0, nb = 0;
  for (let i = 0; i < a.length; i++) { dot += a[i] * b[i]; na += a[i] * a[i]; nb += b[i] * b[i]; }
  return na > 0 && nb > 0 ? dot / Math.sqrt(na * nb) : 0;
}
export async function checkBanEvasion(newPlayerId: string, vector: number[]) {
  const recentBans = await db.any(`SELECT br.player_id, fp.vector FROM ban_records br JOIN player_behavioral_fingerprint fp ON br.player_id = fp.player_id WHERE br.applied_at > NOW() - INTERVAL '30 days' AND br.type = 'hard'`);
  for (const b of recentBans) {
    if (cosineSim(vector, b.vector) > 0.85) {
      await db.none(`INSERT INTO ban_records(player_id, type, reason, evidence) VALUES ($1, 'hard', 'ban_evasion', $2)`, [newPlayerId, JSON.stringify({ matchedBannedId: b.player_id })]);
      return true;
    }
  }
  return false;
}

// Modify matchmaking to use shadow pool
export async function selectMatchPool(playerId: string): Promise<'main' | 'shadow'> {
  return (await isShadowBanned(playerId)) ? 'shadow' : 'main';
}

