// src/services/lootGenerator.ts
import { mulberry32, hashSeed } from '../lib/prng';
import { db } from '../db';

const AFFIX_COUNT_DIST = [
  { count: 1, weight: 0.30 }, { count: 2, weight: 0.35 }, { count: 3, weight: 0.20 },
  { count: 4, weight: 0.10 }, { count: 5, weight: 0.04 }, { count: 6, weight: 0.01 }
];
function rarityForAffixCount(c: number): string { return c <= 2 ? 'common' : c === 3 ? 'magic' : c === 4 ? 'rare' : c === 5 ? 'epic' : 'legendary'; }

export async function generateLoot(playerId: string, monsterLevel: number, lootTableId: string, dropSeed: string) {
  const rand = mulberry32(hashSeed(dropSeed));
  const lootTable = await db.one('SELECT * FROM loot_tables WHERE id=$1', [lootTableId]);
  const base = pickWeighted(lootTable.bases, rand);
  const itemPower = Math.floor(monsterLevel * (1 + (rand() - 0.5) * 0.1));
  const affixCount = pickWeighted(AFFIX_COUNT_DIST.map(d => ({ value: d.count, weight: d.weight })), rand) as number;
  const affixPool = await db.any('SELECT * FROM affix_definitions WHERE pool_id = ANY($1) AND tier <= $2', [base.affix_pool_ids, Math.ceil(monsterLevel / 15)]);
  const chosen: any[] = [];
  const usedStats = new Set<string>();
  for (let i = 0; i < affixCount && affixPool.length > 0; i++) {
    const avail = affixPool.filter(a => !usedStats.has(a.stat_id));
    if (avail.length === 0) break;
    const tierWeighted = avail.map(a => ({ ...a, w: a.weight / Math.pow(a.tier, 1.5) }));
    const total = tierWeighted.reduce((s, x) => s + x.w, 0);
    let r = rand() * total;
    let pick: any = null;
    for (const a of tierWeighted) { r -= a.w; if (r <= 0) { pick = a; break; } }
    pick = pick || tierWeighted[0];
    const value = pick.min_value + (pick.max_value - pick.min_value) * rand();
    chosen.push({ code: pick.code, stat_id: pick.stat_id, value, tier: pick.tier });
    usedStats.add(pick.stat_id);
  }
  const allBottomTier = chosen.every(a => a.tier >= 4);
  const vendorTrash = allBottomTier && affixCount <= 2;
  const rarity = rarityForAffixCount(chosen.length);
  const item = await db.one('INSERT INTO player_inventory(player_id, base_id, affixes, item_power, identified, rarity, vendor_trash, generated_seed) VALUES ($1,$2,$3,$4,$5,$6,$7,$8) RETURNING *', [playerId, base.id, JSON.stringify(chosen), itemPower, rarity === 'common', rarity, vendorTrash, BigInt('0x' + dropSeed.slice(0, 16)).toString()]);
  return item;
}
function pickWeighted<T extends { weight: number }>(arr: T[], rand: () => number): T {
  const total = arr.reduce((s, x) => s + x.weight, 0);
  let r = rand() * total;
  for (const x of arr) { r -= x.weight; if (r <= 0) return x; }
  return arr[arr.length - 1];
}

export async function identifyItem(playerId: string, itemId: string) {
  await db.none('UPDATE player_inventory SET identified = true WHERE id=$1 AND player_id=$2 AND identified = false', [itemId, playerId]);
}

export async function autoSellVendorTrash(playerId: string) {
  const trash = await db.any('SELECT id, item_power FROM player_inventory WHERE player_id=$1 AND vendor_trash=true AND equipped=false', [playerId]);
  if (trash.length === 0) return { sold: 0 };
  const goldGained = trash.reduce((s, t) => s + Math.floor(t.item_power * 2), 0);
  await db.tx(async tx => {
    await tx.none('DELETE FROM player_inventory WHERE id = ANY($1)', [trash.map(t => t.id)]);
    await tx.none('UPDATE players SET soft_balance = soft_balance + $1 WHERE id=$2', [goldGained, playerId]);
  });
  return { sold: trash.length, goldGained };
}

