// src/services/streakService.ts
import { db } from '../db';
import { applyCurrencyChange } from './economyService';

export async function claimDaily(playerId: string) {
  return db.tx(async tx => {
    const s = await tx.one('SELECT * FROM player_streak WHERE player_id=$1 FOR UPDATE', [playerId]);
    const now = new Date();
    const lastClaim = s.last_claim_at ? new Date(s.last_claim_at) : null;
    const hoursSince = lastClaim ? (now.getTime() - lastClaim.getTime()) / 3600000 : Infinity;
    if (hoursSince < 20) throw new Error('claim_too_soon');
    let newStreak = s.current_streak;
    let usedGrace = false;
    if (hoursSince < 36) {
      newStreak += 1;
    } else if (hoursSince < 48 && s.grace_tokens > 0) {
      newStreak += 1;
      usedGrace = true;
    } else {
      newStreak = 1;
    }
    const cappedDay = Math.min(newStreak, 30);
    const baseReward = 100;
    const reward = Math.floor(baseReward * Math.pow(1.15, cappedDay));
    const milestones = [7, 14, 30, 60, 100];
    const milestone = milestones.find(m => m === newStreak);
    const milestoneBonus = milestone ? { type: 'chest', tier: milestone >= 60 ? 'legendary' : milestone >= 14 ? 'epic' : 'rare' } : null;
    let newGraceTokens = s.grace_tokens - (usedGrace ? 1 : 0);
    const graceEarned = Math.floor(newStreak / 7) > Math.floor((newStreak - 1) / 7);
    if (graceEarned) newGraceTokens = Math.min(2, newGraceTokens + 1);
    const newLongest = Math.max(s.longest_streak, newStreak);
    await tx.none('UPDATE player_streak SET current_streak=$1, longest_streak=$2, last_claim_at=NOW(), grace_tokens=$3, grace_earned_total=$4, total_claims=total_claims+1 WHERE player_id=$5',
      [newStreak, newLongest, newGraceTokens, s.grace_earned_total + (graceEarned ? 1 : 0), playerId]);
    await tx.none('INSERT INTO streak_claim_log(player_id, day, claim_at, reward_payload, used_grace) VALUES ($1,$2,NOW(),$3,$4)', [playerId, newStreak, JSON.stringify({ currency: reward, milestone: milestoneBonus }), usedGrace]);
    await applyCurrencyChange({ playerId, currency: 'soft', delta: reward, reason: 'daily_quest', referenceId: `streak:${newStreak}`, idempotencyKey: `streak:${playerId}:${newStreak}:${Math.floor(now.getTime() / 86400000)}` });
    return { newStreak, reward, usedGrace, graceEarned, milestone: milestoneBonus, graceTokens: newGraceTokens };
  });
}

export async function getStreakStatus(playerId: string) {
  const s = await db.one('SELECT * FROM player_streak WHERE player_id=$1', [playerId]);
  const now = new Date();
  const lastClaim = s.last_claim_at ? new Date(s.last_claim_at) : null;
  const hoursSince = lastClaim ? (now.getTime() - lastClaim.getTime()) / 3600000 : Infinity;
  const canClaim = hoursSince >= 20;
  const inDanger = hoursSince > 30 && hoursSince < 36;
  const graceAvailable = hoursSince >= 36 && hoursSince < 48 && s.grace_tokens > 0;
  const willReset = hoursSince > 48 || (hoursSince > 36 && s.grace_tokens === 0);
  return { ...s, canClaim, inDanger, graceAvailable, willReset, hoursSinceLastClaim: hoursSince };
}

