// src/services/hiddenAchievementService.ts
import { db } from '../db';
export async function recordAttempt(playerId: string, achievementCode: string) {
  return db.tx(async tx => {
    const def = await tx.oneOrNone('SELECT * FROM achievement_defs WHERE code=$1 AND hidden=true', [achievementCode]);
    if (!def) return null;
    const existing = await tx.oneOrNone('SELECT * FROM player_achievement_hints WHERE player_id=$1 AND achievement_code=$2', [playerId, achievementCode]);
    const attempts = (existing?.attempts || 0) + 1;
    const hintTiers = def.hints || [];
    let unlockedTier = existing?.hint_tier_unlocked || 0;
    for (let i = unlockedTier; i < hintTiers.length; i++) {
      if (attempts >= hintTiers[i].tier_threshold) unlockedTier = i + 1;
    }
    await tx.none('INSERT INTO player_achievement_hints(player_id, achievement_code, attempts, hint_tier_unlocked) VALUES ($1,$2,$3,$4) ON CONFLICT (player_id, achievement_code) DO UPDATE SET attempts=$3, hint_tier_unlocked=$4', [playerId, achievementCode, attempts, unlockedTier]);
    return { attempts, unlockedTier, hasNewHint: unlockedTier > (existing?.hint_tier_unlocked || 0) };
  });
}
export async function fetchHint(playerId: string, achievementCode: string, tier: number) {
  const def = await db.one('SELECT * FROM achievement_defs WHERE code=$1', [achievementCode]);
  const hint = def.hints?.[tier - 1];
  if (!hint) return null;
  await db.none('UPDATE player_achievement_hints SET last_shown_at=NOW() WHERE player_id=$1 AND achievement_code=$2', [playerId, achievementCode]);
  return { text: hint.text, tier };
}

