// src/services/lapTimeService.ts
import { db } from '../db';
import { redis } from '../redis';
import { s3 } from '../aws';

const SECTOR_MIN_TIMES: Record<string, number[]> = { 'monza': [25000, 22000, 28000, 24000] };

export async function submitLap(playerId: string, trackId: string, sectorTimes: number[], totalTime: number, ghostBinary: Buffer) {
  if (Math.abs(sectorTimes.reduce((a, b) => a + b, 0) - totalTime) > 50) throw new Error('sector_sum_mismatch');
  const minTimes = SECTOR_MIN_TIMES[trackId];
  if (!minTimes) throw new Error('unknown_track');
  for (let i = 0; i < sectorTimes.length; i++) {
    if (sectorTimes[i] < minTimes[i]) throw new Error(`sector_${i}_too_fast`);
  }
  const expectedGhostLength = Math.ceil(totalTime / 16.66) * 32;
  if (Math.abs(ghostBinary.length - expectedGhostLength) > expectedGhostLength * 0.1) throw new Error('ghost_length_mismatch');
  const trackStats = await db.oneOrNone('SELECT AVG(time_ms) AS mean, STDDEV(time_ms) AS stddev FROM lap_times WHERE track_id=$1 AND validation_status='valid'', [trackId]);
  if (trackStats?.mean && totalTime < trackStats.mean - 3 * trackStats.stddev) await flagForReview(playerId, trackId, totalTime);
  const ghostKey = `ghosts/${trackId}/${playerId}/${Date.now()}.bin`;
  await s3.putObject({ Bucket: 'racing-ghosts', Key: ghostKey, Body: ghostBinary }).promise();
  const lap = await db.one('INSERT INTO lap_times(player_id, track_id, time_ms, sector_times, ghost_url, validation_status) VALUES ($1,$2,$3,$4,$5,$6) RETURNING *',
    [playerId, trackId, totalTime, sectorTimes, ghostKey, 'valid']);
  const pb = await db.oneOrNone('SELECT lt.time_ms FROM player_best pb JOIN lap_times lt ON pb.lap_time_id=lt.id WHERE pb.player_id=$1 AND pb.track_id=$2', [playerId, trackId]);
  if (!pb || totalTime < pb.time_ms) {
    await db.none('INSERT INTO player_best(player_id, track_id, lap_time_id) VALUES ($1,$2,$3) ON CONFLICT (player_id, track_id) DO UPDATE SET lap_time_id=$3', [playerId, trackId, lap.id]);
    await redis.zadd(`leaderboard:track:${trackId}`, totalTime, playerId);
  }
  return { lap, isPB: !pb || totalTime < pb.time_ms };
}
async function flagForReview(playerId: string, trackId: string, time: number) {
  await db.none('INSERT INTO lap_review_queue(player_id, track_id, time_ms) VALUES ($1,$2,$3)', [playerId, trackId, time]);
}

export async function getLeaderboard(trackId: string, offset = 0, limit = 100) {
  const raw = await redis.zrange(`leaderboard:track:${trackId}`, offset, offset + limit - 1, 'WITHSCORES');
  const result: any[] = [];
  for (let i = 0; i < raw.length; i += 2) {
