// src/services/marketEngine.ts
import { db } from '../db';
import { applyCurrencyChange } from './economyService';

export async function placeOrder(playerId: string, itemCode: string, side: 'buy' | 'sell', price: number, quantity: number) {
  return db.tx(async tx => {
    if (side === 'buy') {
      const cost = price * quantity;
      await applyCurrencyChange({ playerId, currency: 'soft', delta: -cost, reason: 'shop_purchase', referenceId: 'market_escrow', idempotencyKey: `market:${playerId}:${Date.now()}:escrow` });
    } else {
      const inv = await tx.one('SELECT quantity FROM player_items WHERE player_id=$1 AND item_code=$2 FOR UPDATE', [playerId, itemCode]);
      if (inv.quantity < quantity) throw new Error('insufficient_items');
      await tx.none('UPDATE player_items SET quantity = quantity - $1 WHERE player_id=$2 AND item_code=$3', [quantity, playerId, itemCode]);
    }
    const order = await tx.one('INSERT INTO market_orders(player_id, item_code, side, price, quantity, filled_quantity, status, expires_at) VALUES ($1,$2,$3,$4,$5,0,$6,NOW()+INTERVAL '7 days') RETURNING *', [playerId, itemCode, side, price, quantity, 'open']);
    await matchOrder(tx, order);
    return order;
  });
}

async function matchOrder(tx: any, order: any) {
  const oppositeSide = order.side === 'buy' ? 'sell' : 'buy';
  const priceCondition = order.side === 'buy' ? 'price <= $3' : 'price >= $3';
  const orderBy = order.side === 'buy' ? 'price ASC' : 'price DESC';
  let remaining = order.quantity;
  while (remaining > 0) {
    const counter = await tx.oneOrNone(`SELECT * FROM market_orders WHERE item_code=$1 AND side=$2 AND ${priceCondition} AND status='open' AND filled_quantity < quantity ORDER BY ${orderBy}, listed_at ASC LIMIT 1 FOR UPDATE`, [order.item_code, oppositeSide, order.price]);
    if (!counter) break;
    const matchQty = Math.min(remaining, counter.quantity - counter.filled_quantity);
    const tradePrice = counter.price;
    const fee = Math.floor(matchQty * tradePrice * 0.05);
    const seller = order.side === 'sell' ? order.player_id : counter.player_id;
    const buyer = order.side === 'buy' ? order.player_id : counter.player_id;
    await tx.none('INSERT INTO market_trades(item_code, price, quantity, buyer_id, seller_id, fee_amount) VALUES ($1,$2,$3,$4,$5,$6)', [order.item_code, tradePrice, matchQty, buyer, seller, fee]);
    await applyCurrencyChange({ playerId: seller, currency: 'soft', delta: matchQty * tradePrice - fee, reason: 'market_sale' as any, referenceId: `trade:${order.item_code}`, idempotencyKey: `market:trade:${order.id}:${counter.id}:${remaining}` });
    await tx.none('UPDATE market_orders SET filled_quantity = filled_quantity + $1, status = CASE WHEN filled_quantity + $1 = quantity THEN 'filled' ELSE 'open' END WHERE id=$2', [matchQty, counter.id]);
    await tx.none('UPDATE market_orders SET filled_quantity = filled_quantity + $1, status = CASE WHEN filled_quantity + $1 = quantity THEN 'filled' ELSE 'open' END WHERE id=$2', [matchQty, order.id]);
    if (order.side === 'buy') await tx.none('INSERT INTO player_items(player_id, item_code, quantity) VALUES ($1,$2,$3) ON CONFLICT (player_id, item_code) DO UPDATE SET quantity = player_items.quantity + $3', [buyer, order.item_code, matchQty]);
    if (order.side === 'sell') { /* counter is the buy; their escrow already deducted, item granted */ await tx.none('INSERT INTO player_items(player_id, item_code, quantity) VALUES ($1,$2,$3) ON CONFLICT (player_id, item_code) DO UPDATE SET quantity = player_items.quantity + $3', [buyer, order.item_code, matchQty]); }
    remaining -= matchQty;
  }
}

// src/jobs/manipulationDetector.ts
import { Worker } from 'bullmq';
new Worker('manipulation-detector', async () => {
  const items = await db.any(`SELECT DISTINCT item_code FROM market_trades WHERE executed_at > NOW() - INTERVAL '24 hours'`);
  for (const it of items) {
    const stats = await db.one(`SELECT AVG(price) AS mean, STDDEV(price) AS stddev FROM market_trades WHERE item_code=$1 AND executed_at > NOW() - INTERVAL '7 days'`, [it.item_code]);
    const anomalous = await db.any(`SELECT player_id, COUNT(*) AS cnt, AVG(price) AS avg_price FROM market_orders WHERE item_code=$1 AND listed_at > NOW() - INTERVAL '24 hours' GROUP BY player_id HAVING ABS(AVG(price) - $2) > 3 * $3`, [it.item_code, stats.mean, stats.stddev]);
    for (const a of anomalous) await db.none('INSERT INTO market_manipulation_flags(player_id, item_code, evidence) VALUES ($1,$2,$3)', [a.player_id, it.item_code, JSON.stringify(a)]);
  }
  const washTrades = await db.any(`WITH recent AS (SELECT buyer_id, seller_id, item_code, COUNT(*) AS cnt FROM market_trades WHERE executed_at > NOW() - INTERVAL '24 hours' GROUP BY buyer_id, seller_id, item_code) SELECT r1.buyer_id AS a, r1.seller_id AS b FROM recent r1 JOIN recent r2 ON r1.buyer_id = r2.seller_id AND r1.seller_id = r2.buyer_id AND r1.item_code = r2.item_code WHERE r1.cnt > 5 AND r2.cnt > 5`);
  for (const w of washTrades) await db.none('INSERT INTO market_manipulation_flags(player_id, evidence) VALUES ($1, $2)', [w.a, JSON.stringify({ wash_trade_with: w.b })]);
});

