// src/services/quickMatchService.ts
import { redis } from '../redis';
import { db } from '../db';

export async function enqueueQuickMatch(playerId: string, mmr: number) {
  await redis.zadd('qm:queue', mmr, playerId);
  const skillBand = 100;
  const tStart = Date.now();
  const T = mmr > 2000 ? 8000 : 3000;
  let lobby: any[] = [{ id: playerId, isBot: false, mmr }];
  while (lobby.length < 4 && Date.now() - tStart < T) {
    const candidates = await redis.zrangebyscore('qm:queue', mmr - skillBand, mmr + skillBand, 'LIMIT', 0, 4);
    const available = candidates.filter(c => c !== playerId && !lobby.find(l => l.id === c));
    for (const c of available) { if (lobby.length < 4) { lobby.push({ id: c, isBot: false, mmr: parseFloat((await redis.zscore('qm:queue', c)) || '0') }); await redis.zrem('qm:queue', c); } }
    if (lobby.length < 4) await new Promise(r => setTimeout(r, 500));
  }
  while (lobby.length < 4) {
    const bot = await db.one(`SELECT * FROM bot_profiles WHERE mmr BETWEEN $1 AND $2 ORDER BY RANDOM() LIMIT 1`, [mmr - 200, mmr + 50]);
    lobby.push({ id: bot.id, isBot: true, mmr: bot.mmr, name: bot.name, avatar_url: bot.avatar_url });
  }
  await redis.zrem('qm:queue', playerId);
  const match = await db.one('INSERT INTO matches(participants) VALUES ($1) RETURNING id', [JSON.stringify(lobby)]);
  for (const p of lobby) if (!p.isBot) io.to(`player:${p.id}`).emit('match_starting', { matchId: match.id, lobby });
  startSwapWatcher(match.id, lobby);
  return { matchId: match.id, lobby };
}

async function startSwapWatcher(matchId: string, lobby: any[]) {
  const interval = setInterval(async () => {
    for (let i = 0; i < lobby.length; i++) {
      if (!lobby[i].isBot) continue;
      const candidates = await redis.zrangebyscore('qm:queue', lobby[i].mmr - 100, lobby[i].mmr + 100, 'LIMIT', 0, 1);
      if (candidates.length > 0) {
        const realPlayer = candidates[0];
        await redis.zrem('qm:queue', realPlayer);
        lobby[i] = { id: realPlayer, isBot: false, mmr: lobby[i].mmr };
        io.to(`match:${matchId}`).emit('lobby_update', { lobby });
      }
    }
  }, 5000);
  setTimeout(() => clearInterval(interval), 30000);
}

// Bot AI runs in dedicated worker mimicking realistic timing
import { Worker } from 'bullmq';
new Worker('bot-controller', async job => {
  const { matchId, botId, state } = job.data;
  await new Promise(r => setTimeout(r, 200 + Math.random() * 600));
  const action = decideBotAction(state, botId);
  await applyMatchAction(matchId, botId, action);
});

