import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { useGLTF, useAnimations } from '@react-three/drei';
import { useRef, useEffect, useState } from 'react';
import * as THREE from 'three';

function CharacterModel({ url, signaturePose, statusEffect }: any) {
  const group = useRef<THREE.Group>(null);
  const { scene, animations } = useGLTF(url);
  const { actions, mixer } = useAnimations(animations, group);
  const { mouse } = useThree();
  const headBone = useRef<THREE.Object3D | null>(null);
  useEffect(() => {
    scene.traverse(obj => { if (obj.name === 'Head' || obj.name === 'head') headBone.current = obj; });
    actions.idle?.play();
  }, [scene, actions]);
  useEffect(() => {
    if (signaturePose && actions.signature) { actions.idle?.fadeOut(0.2); actions.signature.reset().fadeIn(0.2).play(); setTimeout(() => { actions.signature?.fadeOut(0.3); actions.idle?.reset().fadeIn(0.3).play(); }, 2000); }
  }, [signaturePose, actions]);
  useFrame((state, delta) => {
    mixer.update(delta);
    if (group.current) {
      group.current.scale.y = 1 + 0.02 * Math.sin(state.clock.elapsedTime * 1.2);
    }
    if (headBone.current) {
      const target = new THREE.Euler(THREE.MathUtils.clamp(-mouse.y * 0.4, -0.4, 0.4), THREE.MathUtils.clamp(mouse.x * 0.4, -0.4, 0.4), 0);
      headBone.current.rotation.x += (target.x - headBone.current.rotation.x) * 0.1;
      headBone.current.rotation.y += (target.y - headBone.current.rotation.y) * 0.1;
    }
    if (statusEffect && group.current) {
      group.current.traverse(obj => {
        const mesh = obj as THREE.Mesh;
        if (!mesh.material) return;
        const mat = mesh.material as any;
        if (statusEffect === 'fire' && mat.emissive) { mat.emissive.setHex(0xff4400); mat.emissiveIntensity = 0.5 + 0.3 * Math.sin(state.clock.elapsedTime * 10); }
        else if (statusEffect === 'frozen' && mat.emissive) { mat.color?.setHex(0x88aaff); mat.emissive.setHex(0x4488ff); mat.emissiveIntensity = 0.3; }
      });
    }
  });
  return <primitive ref={group} object={scene} />;
}

export function CharacterShowcase({ character }: any) {
  const [pose, setPose] = useState(0);
  const [status, setStatus] = useState<string | null>(null);
  return (
    <div className='w-full h-96 bg-gradient-to-b from-slate-900 to-slate-950 rounded-2xl relative cursor-pointer' onClick={() => setPose(p => p + 1)}>
      <Canvas camera={{ position: [0, 1.2, 2.5] }} shadows>
        <ambientLight intensity={0.3} />
        <directionalLight position={[5, 5, 5]} intensity={1.2} castShadow />
        <CharacterModel url={character.model_url} signaturePose={pose} statusEffect={status} />
      </Canvas>
      <div className='absolute bottom-3 left-3 right-3 flex justify-between items-center'>
        <div>
          <div className='text-xs text-slate-400 uppercase tracking-widest'>{character.archetype}</div>
          <div className='text-xl font-bold text-white'>{character.name}</div>
        </div>
        <div className='flex gap-2'>
          {['fire', 'frozen', 'normal'].map(s => (
            <button key={s} onClick={(e) => { e.stopPropagation(); setStatus(s === 'normal' ? null : s); }} className='px-2 py-1 text-xs bg-slate-800 text-white rounded'>{s}</button>
          ))}
        </div>
      </div>
    </div>
  );
}

