// src/services/friendService.ts
import { db } from '../db';
const TIER_THRESHOLDS = { good: 0, great: 7, ultra: 30, best: 90 };

export async function sendGift(senderId: string, recipientId: string, locationItems: any[]) {
  return db.tx(async tx => {
    const today = new Date().toISOString().slice(0, 10);
    const sentCount = await tx.one(`SELECT COALESCE(sent_count, 0) AS c FROM daily_gift_counts WHERE player_id=$1 AND date=$2`, [senderId, today]);
    if (sentCount.c >= 20) throw new Error('daily_send_cap_reached');
    const friendship = await tx.one(`SELECT * FROM friendships WHERE LEAST(player_a, player_b)=$1 AND GREATEST(player_a, player_b)=$2 FOR UPDATE`, [senderId < recipientId ? senderId : recipientId, senderId > recipientId ? senderId : recipientId]);
    if (!friendship) throw new Error('not_friends');
    await tx.none('INSERT INTO pending_gifts(sender_id, recipient_id, items) VALUES ($1,$2,$3)', [senderId, recipientId, JSON.stringify(locationItems)]);
    await tx.none(`INSERT INTO daily_gift_counts(player_id, date, sent_count) VALUES ($1, $2, 1) ON CONFLICT (player_id, date) DO UPDATE SET sent_count = daily_gift_counts.sent_count + 1`, [senderId, today]);
    return { sent: true };
  });
}

export async function openGift(recipientId: string, giftId: string) {
  return db.tx(async tx => {
    const gift = await tx.one('SELECT * FROM pending_gifts WHERE id=$1 AND recipient_id=$2 AND opened_at IS NULL FOR UPDATE', [giftId, recipientId]);
    const today = new Date().toISOString().slice(0, 10);
    const openCount = await tx.oneOrNone('SELECT opened_count FROM daily_gift_counts WHERE player_id=$1 AND date=$2', [recipientId, today]);
    if ((openCount?.opened_count || 0) >= 100) throw new Error('daily_open_cap_reached');
    const sender = gift.sender_id;
    const a = sender < recipientId ? sender : recipientId;
    const b = sender < recipientId ? recipientId : sender;
    const friendship = await tx.one('SELECT * FROM friendships WHERE player_a=$1 AND player_b=$2 FOR UPDATE', [a, b]);
    const todayKey = today;
    const alreadyInteractedToday = friendship.last_interaction_date === todayKey;
    let tierUpReward = null;
    if (!alreadyInteractedToday) {
      const newCount = friendship.interaction_count + 1;
      let newTier = friendship.tier;
      for (const [t, threshold] of Object.entries(TIER_THRESHOLDS)) if (newCount >= threshold) newTier = t;
      if (newTier !== friendship.tier) tierUpReward = { tier: newTier, reward_xp: 500 * Math.pow(2, ['good','great','ultra','best'].indexOf(newTier)) };
      await tx.none('UPDATE friendships SET interaction_count=$1, tier=$2, last_interaction_date=$3 WHERE player_a=$4 AND player_b=$5', [newCount, newTier, todayKey, a, b]);
    }
    const isLucky = Math.random() < 0.05;
    await tx.none('UPDATE pending_gifts SET opened_at=NOW(), was_lucky=$1 WHERE id=$2', [isLucky, giftId]);
    await tx.none(`INSERT INTO daily_gift_counts(player_id, date, opened_count) VALUES ($1, $2, 1) ON CONFLICT (player_id, date) DO UPDATE SET opened_count = daily_gift_counts.opened_count + 1`, [recipientId, today]);
    return { items: gift.items, lucky: isLucky, tierUp: tierUpReward };
  });
}

export async function getFriends(playerId: string) {
  return db.any(`SELECT CASE WHEN player_a=$1 THEN player_b ELSE player_a END AS friend_id, tier, interaction_count, became_friends_at FROM friendships WHERE player_a=$1 OR player_b=$1`, [playerId]);
}

