// src/services/replayVerifier.ts
import { db } from '../db';
import { runPuzzleSimulator } from '../shared/puzzleSim';

export async function submitSolve(playerId: string, puzzleId: string, claimedTime: number, replay: any[]) {
  if (replay.length > 10000) throw new Error('replay_too_long');
  const puzzle = await db.one('SELECT * FROM puzzles WHERE id=$1', [puzzleId]);
  const simulationResult = runPuzzleSimulator(puzzle.initial_state, replay, puzzle.solution_target);
  if (!simulationResult.solved) return { verified: false, reason: 'replay_does_not_solve' };
  if (Math.abs(simulationResult.finalTime - claimedTime) > 100) return { verified: false, reason: 'time_mismatch' };
  const flags: any = {};
  if (claimedTime < puzzle.theoretical_min_time) flags.below_min_time = true;
  const userStats = await db.oneOrNone('SELECT * FROM player_solve_stats WHERE player_id=$1 AND puzzle_set=$2', [playerId, puzzle.set_id]);
  if (userStats && userStats.solve_count > 20) {
    const cv = userStats.std_dev / userStats.mean_time;
    if (cv < 0.05) flags.suspiciously_consistent = true;
  }
  const verified = Object.keys(flags).length === 0;
  await db.tx(async tx => {
    await tx.none('INSERT INTO puzzle_submissions(player_id, puzzle_id, claimed_time_ms, replay, server_verified, anomaly_flags) VALUES ($1,$2,$3,$4,$5,$6)', [playerId, puzzleId, claimedTime, JSON.stringify(replay), verified, JSON.stringify(flags)]);
    if (verified) {
      await tx.none(`INSERT INTO player_solve_stats(player_id, puzzle_set, mean_time, std_dev, solve_count) VALUES ($1, $2, $3, 0, 1) ON CONFLICT (player_id, puzzle_set) DO UPDATE SET solve_count = player_solve_stats.solve_count + 1, mean_time = (player_solve_stats.mean_time * player_solve_stats.solve_count + $3) / (player_solve_stats.solve_count + 1)`, [playerId, puzzle.set_id, claimedTime]);
      await tx.none('INSERT INTO leaderboard(puzzle_id, player_id, time_ms) VALUES ($1, $2, $3) ON CONFLICT (puzzle_id, player_id) DO UPDATE SET time_ms = LEAST(leaderboard.time_ms, $3)', [puzzleId, playerId, claimedTime]);
    }
  });
  return { verified, reason: verified ? null : 'flagged_for_review' };
}

// src/shared/puzzleSim.ts — DETERMINISTIC, runs same on client and server
export function runPuzzleSimulator(initialState: any, replay: any[], target: any): { solved: boolean; finalTime: number; finalState: any } {
  let state = JSON.parse(JSON.stringify(initialState));
  let lastT = 0;
  for (const event of replay) {
    if (event.t < lastT) return { solved: false, finalTime: 0, finalState: state };
    lastT = event.t;
    state = applyEvent(state, event);
  }
  return { solved: isMatch(state, target), finalTime: lastT, finalState: state };
}
function applyEvent(state: any, ev: any): any { return state; }
function isMatch(state: any, target: any): boolean { return JSON.stringify(state) === JSON.stringify(target); }

