// src/components/PuzzlePlayer.tsx
import { useEffect, useRef, useState } from 'react';
export function PuzzlePlayer({ puzzleId, initialState, onComplete }: any) {
  const [state, setState] = useState(initialState);
  const eventLog = useRef<any[]>([]);
  const startTime = useRef(Date.now());
  const recordEvent = (action: any) => { eventLog.current.push({ t: Date.now() - startTime.current, action }); };
  const onKey = (key: string) => {
    recordEvent({ type: 'key', key });
    const next = applyEvent(state, { type: 'key', key });
    setState(next);
    if (isSolved(next)) submit();
  };
  const submit = async () => {
    const claimedTime = Date.now() - startTime.current;
    const res = await fetch('/api/puzzle/submit', { method: 'POST', body: JSON.stringify({ puzzleId, claimedTime, replay: eventLog.current }) });
    const data = await res.json();
    onComplete(data);
  };
  return (
    <div onKeyDown={e => onKey(e.key)} tabIndex={0} className='outline-none'>
      {/* puzzle render */}
    </div>
  );
}
function applyEvent(s: any, e: any) { return s; }
function isSolved(s: any) { return false; }
